export interface Drill {
  id: string;
  name: string;
  category: string;
  duration: number;
  difficulty: 'beginner' | 'intermediate' | 'advanced';
  equipment: string[];
  type: 'warmup' | 'skill' | 'shooting' | 'conditioning';
  summary: string;
  steps: string[];
  coachingPoints: string[];
  commonMistakes: string[];
  variations?: string[];
  videoUrl?: string;
}

export interface DrillCategory {
  name: string;
  color: string;
  description: string;
  drills: Drill[];
}

