const SHOOTING_DRILLS: Drill[] = [
  { id:'sh-1',name:'Form Shooting',category:'Shooting',duration:5,difficulty:'beginner',equipment:['ball','hoop'],type:'shooting',
    summary:'Perfect your shooting mechanics from close range before moving out.',
    steps:['Stand 3-4 feet from the basket.','Shoot with one hand only. Guide hand off.','Focus on: elbow under ball, wrist snap, follow through.','Make 10 in a row, then move back to 5 feet.','Continue to 8 feet if you\'re making 7/10.'],
    coachingPoints:['Elbow directly under the ball.','Snap your wrist and hold your follow through.','Ball should have backspin.','This is your foundation — never stop doing this drill.'],
    commonMistakes:['Elbow flaring out.','Flat release.','Rushing through reps.'],
    youtubeId:'2xDgvuV3mtE' },
  { id:'sh-2',name:'One Hand Form Shooting',category:'Shooting',duration:5,difficulty:'beginner',equipment:['ball','hoop'],type:'shooting',
    summary:'Shoot with your guide hand behind your back to isolate pure shooting mechanics.',
    steps:['Put your guide hand behind your back.','Hold the ball on your shooting hand, balanced on your fingertips.','Shoot from 3 feet. Focus only on your shooting hand mechanics.','Make 10, move to 5 feet. Make 10, move to 8 feet.','If the ball goes left or right, your hand is off-center.'],
    coachingPoints:['The ball should sit on your fingertips, not your palm.','Your index and middle finger should be the last to leave the ball.','The ball should go straight — any sideways drift means alignment is off.','This isolates the shooting hand so you can find problems.'],
    commonMistakes:['Ball sitting on your palm — get it on your fingertips.','Thumb flicking the ball — thumb should be relaxed.','Guide hand sneaking in to help — keep it behind your back.'] },
  { id:'sh-3',name:'BEEF Shooting Drill',category:'Shooting',duration:8,difficulty:'beginner',equipment:['ball','hoop'],type:'shooting',
    summary:'Focus on the BEEF fundamentals: Balance, Eyes, Elbow, Follow-through.',
    steps:['Take 5 shots focusing ONLY on Balance — feet set, shoulder width.','Take 5 shots focusing ONLY on Eyes — locked on the rim.','Take 5 shots focusing ONLY on Elbow — tucked in, under the ball.','Take 5 shots focusing ONLY on Follow-through — held high.','Then take 10 shots putting all four together.','Repeat from 3 different spots on the floor.'],
    coachingPoints:['BEEF is the checklist: Balance, Eyes, Elbow, Follow-through.','By isolating each element, you find which one is breaking down.','If you\'re missing, go through the checklist and find the problem.','Make this your pre-game routine.'],
    commonMistakes:['Trying to fix everything at once — isolate one at a time.','Rushing — this is a mindful shooting drill.','Ignoring one element because it feels fine — check them all.'] },
  { id:'sh-4',name:'Around the World',category:'Shooting',duration:10,difficulty:'beginner',equipment:['ball','hoop'],type:'shooting',
    summary:'Classic shooting game — make shots from spots around the court in order.',
    steps:['Start at the right block.','Make a shot, move to the next spot: right elbow, free throw, left elbow, left block.','If you miss, you can "chance it" — shoot again, but if you miss again, go back to the start.','Or play it safe and stay where you are.','First to complete all spots wins (or do it solo for time).'],
    coachingPoints:['This teaches shot selection and pressure — do you chance it or play safe?','Focus on your form at every spot, even the easy ones.','Track your time and try to beat it each session.'],
    commonMistakes:['Always chancing it — sometimes playing safe is smarter.','Rushing shots to go faster.','Changing your form at different spots.'] },
  { id:'sh-5',name:'Spot Shooting',category:'Shooting',duration:12,difficulty:'intermediate',equipment:['ball','hoop'],type:'shooting',
    summary:'Shoot from specific spots on the floor to build consistency from your game spots.',
    steps:['Pick 5 spots where you normally shoot in games.','Shoot 20 shots from each spot.','Track makes and misses at each spot.','Identify your two weakest spots.','Shoot 20 more from each of those weak spots.'],
    coachingPoints:['Shoot from YOUR spots — where you actually get shots in games.','Same footwork, same rhythm, every shot.','This data tells you where to practice and where you\'re money.','Keep a shooting log over time.'],
    commonMistakes:['Shooting from random spots that aren\'t game shots.','Not tracking your percentages.','Practicing only from your best spots.'] },
  { id:'sh-6',name:'Catch and Shoot',category:'Shooting',duration:8,difficulty:'intermediate',equipment:['ball','hoop'],type:'shooting',
    summary:'Practice receiving a pass and shooting in one smooth motion.',
    steps:['Start at the wing with hands ready — showing a target.','Toss the ball to yourself (or have a partner pass).','Catch with feet already set and shoot immediately.','The catch and shot should be one rhythm — no pause.','15 shots from each spot: corner, wing, top.'],
    coachingPoints:['Hands and feet ready BEFORE the ball arrives.','Catch it in your shot pocket — don\'t catch low and bring it up.','One smooth motion: catch-gather-shoot.','The best shooters in the world are great at catch-and-shoot.'],
    commonMistakes:['Catching and then getting feet set — too slow.','Catching low at your waist and bringing the ball up — catch in your shot pocket.','Extra dribble after the catch — just shoot it.'] },
  { id:'sh-7',name:'Off the Dribble Pull Up',category:'Shooting',duration:10,difficulty:'intermediate',equipment:['ball','hoop'],type:'shooting',
    summary:'The mid-range pull-up jumper off one dribble.',
    steps:['Start at the wing, triple threat.','Jab right, one hard dribble left, pull up.','10 reps going left.','Switch: jab left, one dribble right, pull up. 10 reps.','Repeat from top of key and elbow.'],
    coachingPoints:['Plant your feet hard before shooting.','One dribble only.','Last dribble hard and slightly in front.','Jump straight up.'],
    commonMistakes:['Drifting on the shot.','Too many dribbles.','Not selling the jab step.'] },
  { id:'sh-8',name:'5 Spot Shooting',category:'Shooting',duration:12,difficulty:'intermediate',equipment:['ball','hoop'],type:'shooting',
    summary:'Make 10 shots from five spots around the three-point arc.',
    steps:['Right corner, right wing, top of key, left wing, left corner.','Make 10 from each spot before moving on.','Track total attempts at each spot.','After all 5, shoot 20 more from your worst spot.'],
    coachingPoints:['Feet set BEFORE you catch.','Knees provide power. Bend them.','Same release, same follow through, every time.','Short = more legs. Left/right = check elbow.'],
    commonMistakes:['Fading away.','Not bending knees.','Changing form between spots.'] },
  { id:'sh-9',name:'Mikan Shooting Drill',category:'Shooting',duration:5,difficulty:'beginner',equipment:['ball','hoop'],type:'shooting',
    summary:'Close-range alternating layups to build soft touch and finishing ability.',
    steps:['Stand right next to the basket on the right side.','Make a right hand layup off the glass.','Catch it, step to the left side.','Make a left hand layup.','Continue alternating — 30 makes without the ball touching the ground.'],
    coachingPoints:['Keep the ball above your shoulders the entire time.','Use the backboard every time.','Soft touch — kiss the glass.','If you miss, start over.'],
    commonMistakes:['Bringing the ball down low.','Using the same hand both sides.','Going too fast and missing.'] },
  { id:'sh-10',name:'Elbow Shooting',category:'Shooting',duration:6,difficulty:'beginner',equipment:['ball','hoop'],type:'shooting',
    summary:'Build money from the mid-range elbows — the most efficient shot in basketball.',
    steps:['Right elbow: shoot 15 mid-range jumpers.','Left elbow: shoot 15 more.','Alternate: 2 from right, 2 from left, for 20 more.','Track percentage from each side.'],
    coachingPoints:['Square your feet to the basket.','This should be the most consistent shot in your game.','Use the backboard from the elbows.'],
    commonMistakes:['Fading away from mid-range.','Not squaring up.'] },
  { id:'sh-11',name:'Corner Shooting',category:'Shooting',duration:8,difficulty:'intermediate',equipment:['ball','hoop'],type:'shooting',
    summary:'The corner three is the shortest three-pointer — own it.',
    steps:['Start in the right corner, toes behind the line.','Shoot 20 threes. Track your makes.','Move to the left corner. Shoot 20 more.','Identify which corner is weaker. Shoot 15 more from that side.','Finish with 10 corner threes where you\'re moving into the corner before catching.'],
    coachingPoints:['The corner three is 22 feet vs 23.75 at the top — almost 2 feet shorter.','Get your toes set behind the line. Step-backs from the corner go out of bounds.','This is a role player\'s best friend — if you can hit corner threes, you will always have a roster spot.','Quick release — corner threes are usually off a kick-out with a closeout coming.'],
    commonMistakes:['Stepping on the line — know exactly where you are.','Taking too long to shoot — the closeout is coming.','Not having your feet set before the ball arrives.'] },
  { id:'sh-12',name:'Wing Shooting',category:'Shooting',duration:8,difficulty:'intermediate',equipment:['ball','hoop'],type:'shooting',
    summary:'Build range and consistency from the wings — where most shots happen.',
    steps:['Start at the right wing behind the three-point line.','Shoot 20 threes. Track makes.','Move to the left wing. 20 more.','Then shoot 10 from each wing off one dribble.','Finish with 10 catch-and-shoot from each wing at game speed.'],
    coachingPoints:['The wing is where you\'ll get most of your shots in a real game.','Make sure your feet are angled slightly toward the basket, not parallel to the sideline.','Use your legs — wings are farther than corners.'],
    commonMistakes:['Feet pointing the wrong direction.','Short shots — bend your knees more.','Drifting sideways on the shot.'] },
  { id:'sh-13',name:'Free Throw Routine',category:'Shooting',duration:10,difficulty:'beginner',equipment:['ball','hoop'],type:'shooting',
    summary:'Build an automatic free throw routine you can rely on under pressure.',
    steps:['Step to the line. Take your stance.','Develop a routine: dribble 1-3 times, deep breath, focus on the rim.','Shoot 10 free throws, following your exact routine every time.','Then shoot 50 total free throws. Track your percentage.','If you miss 2 in a row, do 5 push-ups, then shoot 2 more.'],
    coachingPoints:['Your routine should take the same amount of time every single shot.','Pick a specific spot on the rim to aim at — front of the rim, back of the rim, hooks.','The routine builds muscle memory — your body does the same thing every time so your mind doesn\'t have to think.','Track your percentage. You should be shooting 70%+ consistently.'],
    commonMistakes:['Changing your routine between shots.','Rushing when you miss — slow down.','Not having a routine at all — just stepping up and shooting.'] },
  { id:'sh-14',name:'Chair Curl Shooting',category:'Shooting',duration:10,difficulty:'intermediate',equipment:['ball','hoop','chair'],type:'shooting',
    summary:'Simulate coming off a screen using a chair, then catch and shoot.',
    steps:['Place a chair at the elbow.','Start on the block. Sprint and curl tight around the chair.','Catch (toss to yourself or use a partner) and shoot immediately.','15 reps curling right.','Move chair to left elbow. 15 reps curling left.','Then 15 fading away from the chair each side.'],
    coachingPoints:['Rub the chair like it\'s a real screen — get tight.','Hands ready before you come around.','Quick release — catch, set, shoot. No extra dribbles.','Curl if defender goes over, fade if they go under.'],
    commonMistakes:['Running too wide around the chair.','Catching with feet not set.','Slow release.'] },
  { id:'sh-15',name:'Fadeaway Shooting',category:'Shooting',duration:8,difficulty:'advanced',equipment:['ball','hoop'],type:'shooting',
    summary:'Create space by fading away from the defender while maintaining accuracy.',
    steps:['Start on the right block, back to the basket.','Catch the ball, pivot to face up.','Jump backward (fade) while shooting a mid-range jumper.','10 reps from the right block.','10 reps from the left block.','Then try from the elbows — catch, jab, fade.'],
    coachingPoints:['The fade creates space — you don\'t need much, just enough.','Your upper body should stay straight even though your lower body is moving backward.','Release at the peak of your jump.','This is a tough shot — only use it when you need to.'],
    commonMistakes:['Fading too far — you lose power and accuracy.','Leaning your upper body back — stay upright from the waist up.','Using this as your first option — it\'s a counter move.'] },
  { id:'sh-16',name:'Step Back Shooting',category:'Shooting',duration:8,difficulty:'advanced',equipment:['ball','hoop'],type:'shooting',
    summary:'Create separation with a step-back for an open jumper.',
    steps:['Start at the top of key.','Two dribbles toward the basket.','Plant lead foot and step back behind the three-point line.','Catch balance and shoot.','10 reps stepping right, 10 stepping left, 10 straight back.'],
    coachingPoints:['Step back far enough for real separation.','Land on both feet at the same time.','Shoulders square to the basket on landing.','Don\'t rush — the step-back already created your space.'],
    commonMistakes:['Not stepping back far enough.','Landing off-balance.','Traveling — clean gather required.'] },
  { id:'sh-17',name:'Pump Fake One Dribble Shot',category:'Shooting',duration:8,difficulty:'intermediate',equipment:['ball','hoop'],type:'shooting',
    summary:'Use a pump fake to get the defender in the air, then attack for a score.',
    steps:['Start on the wing in triple threat.','Show a convincing pump fake — ball above forehead, eyes on rim.','When defender jumps, one hard dribble past them.','Finish with a pull-up or layup.','10 from each wing, 10 from top of key.'],
    coachingPoints:['Pump fake has to be real — if you wouldn\'t believe it, the defender won\'t.','Eyes on rim during the fake.','After the fake, attack the defender\'s hip.','One dribble only.'],
    commonMistakes:['Lazy fake — get the ball up.','Too many dribbles after.','Not attacking immediately after the fake.'] },
  { id:'sh-18',name:'Transition Pull Up',category:'Shooting',duration:8,difficulty:'intermediate',equipment:['ball','hoop','full court'],type:'shooting',
    summary:'Practice pulling up for a jumper in transition instead of always going to the rim.',
    steps:['Start at the opposite baseline.','Push the ball up the court at full speed.','At the three-point line, pull up for a transition three.','Sprint back, do it again — this time pull up at the free throw line.','Alternate between transition threes and mid-range pull-ups.','10 total shots. Track makes.'],
    coachingPoints:['In transition, defenders are scrambling — a pull-up catches them off guard.','You have to be able to stop on a dime at full speed.','The faster you can go from sprint to shot, the more open looks you\'ll get.','Don\'t always go to the rim in transition — mix in pull-ups.'],
    commonMistakes:['Can\'t stop cleanly — practice your stop.','Shooting while still moving forward.','Always going to the rim — the defense expects that.'] },
  { id:'sh-19',name:'Relocation Shooting',category:'Shooting',duration:8,difficulty:'intermediate',equipment:['ball','hoop'],type:'shooting',
    summary:'Move to a new spot after a pass and be ready to catch and shoot.',
    steps:['Start at the right corner.','Toss the ball to an imaginary teammate at the wing.','Relocate — move to the right wing.','The "pass" comes back to you (toss to yourself or partner).','Catch and shoot immediately.','10 reps relocating from each spot.'],
    coachingPoints:['After every pass, MOVE. Never pass and stand.','Relocate to a spot where you can catch and shoot in rhythm.','Be ready before the ball comes — hands and feet ready.','In a real game, this creates open shots for the whole team.'],
    commonMistakes:['Standing still after passing — you have to move.','Relocating to a spot that\'s too close to a teammate.','Not being ready when the ball comes back.'] },
  { id:'sh-20',name:'Partner Pass Shooting',category:'Shooting',duration:10,difficulty:'beginner',equipment:['ball','hoop','partner'],type:'shooting',
    summary:'Catch passes from a partner and shoot — the most game-like shooting drill.',
    steps:['Partner stands at the top of key with the ball.','You start in the corner. Sprint to the wing.','Partner passes. You catch and shoot.','Get your own rebound and pass back to your partner.','Sprint to the other wing. Catch and shoot.','Do 20 total shots, alternating sides.'],
    coachingPoints:['Call for the ball as you move — communicate.','Show a hand target so your partner knows where to pass.','Catch in your shot pocket — ready to shoot.','This is how real game shots happen — off a pass.'],
    commonMistakes:['Not calling for the ball — communicate.','Catching and then getting set — be ready before the catch.','No target hand — show your partner where to throw it.'] },
  { id:'sh-21',name:'Closeout Shooting',category:'Shooting',duration:8,difficulty:'advanced',equipment:['ball','hoop','partner or cone'],type:'shooting',
    summary:'Practice shooting with a closeout coming — game pressure shooting.',
    steps:['Partner starts at the rim. You\'re at the three-point line with the ball.','Partner sprints to close out on you.','Read the closeout and decide: shoot over it, or drive past it.','If they close out hard — drive. If they\'re slow — shoot.','Alternate with partner. 10 reps each.'],
    coachingPoints:['Read the closeout speed. Fast = drive. Slow = shoot.','If you shoot, get it off quickly before they arrive.','If you drive, attack their lead foot — go to the side they\'re leaning.','This is the #1 game situation you\'ll face.'],
    commonMistakes:['Always shooting regardless of the closeout — read it.','Panicking under the closeout — stay calm and make a decision.','Not getting the shot off in time.'] },
  { id:'sh-22',name:'Quick Release Shooting',category:'Shooting',duration:8,difficulty:'advanced',equipment:['ball','hoop'],type:'shooting',
    summary:'Minimize your shooting motion to get shots off faster.',
    steps:['Start at the three-point line.','Catch and shoot as fast as possible — try to release in under 0.7 seconds.','Don\'t sacrifice form for speed — it still has to be a good shot.','10 from each spot.','Have a partner count "one-Mississippi" — you should shoot before they finish.'],
    coachingPoints:['Quick release starts with early preparation — feet and hands ready before the catch.','Catch the ball in your shot pocket, not at your waist.','A quick release makes every shot more open because the defender has less time to contest.','Steph Curry\'s release is about 0.4 seconds. Aim for under 0.8.'],
    commonMistakes:['Sacrificing form for speed — a fast miss is still a miss.','Catching low and then bringing the ball up — start high.','Not having feet set — you can\'t be quick if your base isn\'t ready.'] },
  { id:'sh-23',name:'Shooting Off Screens',category:'Shooting',duration:10,difficulty:'advanced',equipment:['ball','hoop','cones'],type:'shooting',
    summary:'Practice coming off down screens and flare screens for catch-and-shoot opportunities.',
    steps:['Place cones at the block and elbow to simulate screens.','Start on the block. Curl off the elbow screen — catch and shoot at the wing.','Start on the block. Fade off the elbow screen — catch and shoot at the corner.','Start at the wing. Come off a flare screen (cone at wing) — catch and shoot at the corner.','15 reps of each type.'],
    coachingPoints:['Set up your defender before using the screen — walk them down.','Read the defense: curl if they trail, fade if they go over.','Hands ready before you come off the screen.','Tight to the screen — rub shoulders with the cone.'],
    commonMistakes:['Going wide around the screen — stay tight.','Not reading the defense — always make a decision based on how they play the screen.','Catching and dribbling — the whole point is to catch and shoot.'] },
  { id:'sh-24',name:'3 Point Spot Shooting',category:'Shooting',duration:10,difficulty:'intermediate',equipment:['ball','hoop'],type:'shooting',
    summary:'Build consistency and track your percentage from every spot behind the arc.',
    steps:['Shoot 10 from the right corner. Track makes.','Shoot 10 from the right wing.','Shoot 10 from the top of the key.','Shoot 10 from the left wing.','Shoot 10 from the left corner.','Total: 50 shots. Track your overall percentage and each spot.'],
    coachingPoints:['This is your shooting report card. Know your numbers.','Identify your best and worst spots. Practice the worst ones more.','Aim for 35% overall from three to start. Build toward 40%.','Keep a shooting log — track this weekly to see improvement.'],
    commonMistakes:['Not tracking your numbers — the data matters.','Only shooting from your favorite spot.','Getting discouraged by a bad round — shoot through it.'] },
  { id:'sh-25',name:'100 Makes Shooting Drill',category:'Shooting',duration:20,difficulty:'intermediate',equipment:['ball','hoop'],type:'shooting',
    summary:'Don\'t leave the gym until you make 100 shots — builds endurance and consistency.',
    steps:['Pick your 5 favorite spots on the floor.','Shoot from any spot until you make 100 total shots.','Track how many attempts it takes to get to 100.','Move around — don\'t stand in one spot.','Mix catch-and-shoot and off-the-dribble shots.','Your goal: 100 makes in under 200 attempts (50%).'],
    coachingPoints:['This is a grind drill. It builds mental toughness and shooting endurance.','Your last 20 shots should look like your first 20 — same form when tired.','Move between spots to simulate game movement.','Track your total attempts each time — that number should go down week over week.'],
    commonMistakes:['Standing in one spot for all 100 — move around.','Losing form when tired — stay disciplined.','Counting makes loosely — be honest with yourself.'] },
  { id:'sh-26',name:'Elbow Alignment Drill',category:'Shooting',duration:6,difficulty:'beginner',equipment:['ball','hoop','wall'],type:'shooting',
    summary:'Diagnose and fix elbow flare by shooting next to a wall — your elbow physically can\'t flare out.',
    steps:['Stand 5 feet from the basket, RIGHT side of your shooting hand against a wall.','Get into your shooting form. Your shooting elbow should not touch the wall.','If your elbow hits the wall, your elbow is flaring out — that\'s your problem.','Shoot 10 form shots. Elbow stays off the wall the entire time.','Move to 8 feet. 10 more shots.','Move to free throw line. 10 more shots.'],
    coachingPoints:['Elbow flare is the #1 cause of inconsistent shooting.','The wall is a physical reminder — it can\'t lie to you.','Your elbow should be directly under the ball, pointing at the rim.','When you fix elbow alignment, your shot becomes a straight line instead of a curve.'],
    commonMistakes:['Compensating by twisting your body away from the wall — keep your shoulders square.','Elbow touching the wall and ignoring it — fix it.','Only doing this once and forgetting — make it part of your regular shooting routine.'] },
  { id:'sh-27',name:'Guide Hand Removal Drill',category:'Shooting',duration:6,difficulty:'beginner',equipment:['ball','hoop'],type:'shooting',
    summary:'Diagnose guide hand interference by shooting with your guide hand off the ball entirely.',
    steps:['Stand 5 feet from the basket.','Hold the ball with your shooting hand only — guide hand at your side.','Shoot the ball using only your shooting hand.','Watch the ball flight: if it goes left or right, your shooting hand alignment is off.','Make 10 from 5 feet. Move to 8 feet. Make 10.','Then add the guide hand back, but DO NOT let it push the ball. Guide hand only steadies — it never moves.','Make 10 from each spot with the guide hand back on.'],
    coachingPoints:['The guide hand is the silent killer of jumpshots — most missed shots are because the off hand pushes.','Your guide hand should leave the ball BEFORE the shooting hand releases.','If your shot goes left, your guide hand is pushing.','Watch the ball flight — it tells you everything.'],
    commonMistakes:['Guide hand thumb pushing the ball — keep it relaxed.','Guide hand fingers gripping — they should be loose.','Adding the guide hand back too soon — feel the difference first.'] },
  { id:'sh-28',name:'Dip Fix Drill',category:'Shooting',duration:6,difficulty:'intermediate',equipment:['ball','hoop'],type:'shooting',
    summary:'Eliminate the "dip" — the bad habit of lowering the ball before your shot.',
    steps:['Catch the ball in your shot pocket — high, near your chest, not low at your waist.','Shoot WITHOUT lowering the ball first. Catch high, shoot from there.','5 form shots from 5 feet, focusing on no dip.','5 from 8 feet.','Then have a partner pass to you (or toss to yourself). Catch in shot pocket. No dip. Shoot.','15 catch-and-shoot reps from the wing.'],
    coachingPoints:['The dip wastes time — every dip is an extra fraction of a second the defender has to contest.','Catch the ball where you\'re going to shoot it. No moving it down first.','This is what makes shooters quick — eliminating wasted motion.','Steph Curry barely dips — that\'s why his release is so fast.'],
    commonMistakes:['Catching low at your waist — catch in your shot pocket.','Dipping out of habit — film yourself to see if you\'re doing it.','Sacrificing power for speed — your legs provide power, not your dip.'] },
];

// ============================================================
// FINISHING (27 drills)
// ============================================================
const FINISHING_DRILLS: Drill[] = [
  { id:'fn-1',name:'Mikan Drill',category:'Finishing',duration:5,difficulty:'beginner',equipment:['ball','hoop'],type:'skill',
    summary:'Continuous alternating layups to build touch around the rim.',
    steps:['Right side: right hand layup.','Catch, step to left: left hand layup.','Continue alternating, ball never touches ground.','30 consecutive makes. Miss = restart.'],
    coachingPoints:['Keep ball high.','Use backboard every time.','Soft touch.','Stay on your toes.'],
    commonMistakes:['Ball too low between makes.','Same hand both sides.','Too fast, losing control.'] },
  { id:'fn-2',name:'Reverse Mikan Drill',category:'Finishing',duration:5,difficulty:'intermediate',equipment:['ball','hoop'],type:'skill',
    summary:'Continuous reverse layups from both sides to build ambidextrous finishing.',
    steps:['Start on the right side under the basket.','Reverse layup with your right hand — ball goes on the left side of the rim.','Catch, move to left side.','Reverse layup with left hand — ball goes on right side of rim.','20 consecutive makes.'],
    coachingPoints:['Extend the ball away from where a defender would be.','Use the backboard from the reverse angle.','This is harder than regular Mikan — the angle is less forgiving.','Soft touch is even more important on reverses.'],
    commonMistakes:['Going too far under the basket.','Using the wrong hand — right side approach = right hand reverse.','Not using the backboard.'] },
  { id:'fn-3',name:'Power Layups',category:'Finishing',duration:8,difficulty:'beginner',equipment:['ball','hoop'],type:'skill',
    summary:'Finish strong through contact with two-foot power layups.',
    steps:['Right block: one dribble, jump off both feet, two hand power finish.','10 from right, 10 from left.','Then drive from the wing, power finish at the rim.','10 drives each side.'],
    coachingPoints:['Two feet, two hands. That\'s the power move.','Jump INTO contact — initiate it.','Keep ball high. Chin it.','Land balanced for the and-one.'],
    commonMistakes:['Finishing softly.','Ball down low where it gets stripped.','Jumping off one foot.'] },
  { id:'fn-4',name:'Weak Hand Layups',category:'Finishing',duration:10,difficulty:'beginner',equipment:['ball','hoop'],type:'skill',
    summary:'Dedicated weak hand finishing from every angle.',
    steps:['Left block: 10 left hand layups.','Left wing: drive left, 10 left hand layups.','Top of key going left: 10 left hand layups.','Baseline left: 10 reverse left hand layups.','10 left hand finger rolls from the lane.'],
    coachingPoints:['Jump off right foot for left hand.','Use backboard.','Don\'t switch to strong hand when it gets hard.'],
    commonMistakes:['Wrong foot.','Avoiding backboard.','Switching to strong hand.'] },
  { id:'fn-5',name:'Euro Step Finish',category:'Finishing',duration:8,difficulty:'intermediate',equipment:['ball','hoop'],type:'skill',
    summary:'Master the euro step to finish around shot blockers.',
    steps:['Right wing: drive, long step right, step left, finish left hand.','10 reps right side.','Left wing: drive, long step left, step right, finish right hand.','10 reps left side.'],
    coachingPoints:['First step sells direction. Second step is the counter.','Quick explosive second step.','Ball protected on your hip.','Finish opposite hand from direction.'],
    commonMistakes:['Both steps same direction.','Traveling.','Wrong finishing hand.'] },
  { id:'fn-6',name:'Spin Move Finish',category:'Finishing',duration:8,difficulty:'advanced',equipment:['ball','hoop'],type:'skill',
    summary:'Spin in the lane to create space and finish at the rim.',
    steps:['Free throw line, dribble right toward basket.','Plant left foot, reverse spin to your left.','After spin, finish with left hand.','10 reps spinning left.','Switch: dribble left, spin right, finish right. 10 reps.'],
    coachingPoints:['Tight spin — don\'t drift.','Ball on your hip during spin.','End facing the basket.'],
    commonMistakes:['Drifting from the basket.','Ball exposed during spin.','Traveling.'] },
  { id:'fn-7',name:'Floater Drill',category:'Finishing',duration:8,difficulty:'intermediate',equipment:['ball','hoop'],type:'skill',
    summary:'Develop a soft floater to score over taller defenders.',
    steps:['Free throw line: one dribble, floater from 6-8 feet.','10 right side, 10 left side.','Top of key: drive in for floaters from different angles.','10 more random angles.'],
    coachingPoints:['Push shot off one foot, not a jump shot.','High arc — over an imaginary 7-footer.','Fingertips, not palm.'],
    commonMistakes:['Too hard — this is a touch shot.','Flat arc.','Two foot takeoff.'] },
  { id:'fn-8',name:'Runner Finish',category:'Finishing',duration:8,difficulty:'intermediate',equipment:['ball','hoop'],type:'skill',
    summary:'A one-handed running push shot in the lane — like a floater but with more speed.',
    steps:['Start at the three-point line on the right side.','Drive at full speed toward the basket.','At 8-10 feet, without slowing down, push a one-hand runner off the backboard.','Focus on soft touch while moving at speed.','10 from the right, 10 from the left.'],
    coachingPoints:['The runner is a speed move — don\'t slow down.','Push off one foot (inside foot) and extend toward the basket.','Aim for the top corner of the backboard square.','This is a great way to score in transition.'],
    commonMistakes:['Slowing down before the shot — stay at speed.','Shooting too hard — you need touch at speed.','Not using the backboard.'] },
  { id:'fn-9',name:'Contact Layups',category:'Finishing',duration:8,difficulty:'advanced',equipment:['ball','hoop','pad or partner'],type:'skill',
    summary:'Finish through physical contact at the rim.',
    steps:['Partner in the lane with a pad (or hold a weighted ball).','Drive and finish through the contact.','10 from right, 10 from left.','Focus on absorbing contact and still making the shot.'],
    coachingPoints:['Initiate contact.','Eyes on the rim through contact.','Strong core.','Still need touch, even through contact.'],
    commonMistakes:['Avoiding contact.','Losing focus on rim.','Over-powering the finish.'] },
  { id:'fn-10',name:'Cone Layups',category:'Finishing',duration:8,difficulty:'beginner',equipment:['ball','hoop','cones'],type:'skill',
    summary:'Drive around cones at different spots and finish at the rim.',
    steps:['Place cones at the three-point line, elbow, and lane.','Start at half court. Dribble to the first cone, make a move.','Continue past the second cone with another move.','Finish at the rim.','10 trips using different move combinations.'],
    coachingPoints:['Each cone is a defender — set up your move.','Change speed at each cone.','Always finish strong at the rim.','Use different finishes: layup, power, floater, euro step.'],
    commonMistakes:['Same moves every time.','Jogging through it.','Weak finishes at the rim.'] },
  { id:'fn-11',name:'Baseline Reverse Layups',category:'Finishing',duration:8,difficulty:'intermediate',equipment:['ball','hoop'],type:'skill',
    summary:'Drive baseline and finish with a reverse layup on the other side of the rim.',
    steps:['Start on the right wing.','Drive baseline toward the basket.','Go under the basket and finish with left hand on the other side.','10 reps from right side.','10 reps from left side (finish right hand).'],
    coachingPoints:['Use the rim as a shield.','Extend the ball away from the defender.','Soft touch off the backboard from the reverse angle.','This is a high-IQ finish.'],
    commonMistakes:['Going too far under.','Wrong hand.','No backboard.'] },
  { id:'fn-12',name:'Inside Hand Finish',category:'Finishing',duration:6,difficulty:'intermediate',equipment:['ball','hoop'],type:'skill',
    summary:'Finish with the hand closest to the basket for maximum protection.',
    steps:['Drive from the right wing.','Finish with your RIGHT hand (inside hand) — the hand closest to the basket.','This protects the ball from a shot blocker on your left.','10 reps from the right side.','Drive from the left wing, finish LEFT hand. 10 reps.'],
    coachingPoints:['The inside hand is farther from the defender = harder to block.','Extend the ball toward the rim, away from the defender.','This is the smart finish — not always the strong hand.','Use the backboard.'],
    commonMistakes:['Always finishing with your dominant hand regardless of angle.','Not extending toward the rim.','Forgetting the backboard.'] },
  { id:'fn-13',name:'Outside Hand Finish',category:'Finishing',duration:6,difficulty:'intermediate',equipment:['ball','hoop'],type:'skill',
    summary:'Finish with the hand farthest from the basket to shoot over the defender.',
    steps:['Drive from the right side.','Instead of inside hand, extend and finish with your LEFT hand (outside hand).','This puts the ball high and over a defender who\'s between you and the rim.','10 reps from right side (left hand finish).','10 reps from left side (right hand finish).'],
    coachingPoints:['This is an advanced finish — used when a defender is directly in your path.','Extend the ball high — get it above the defender\'s reach.','Use a soft touch — you\'re reaching over someone.','This is basically a short floater/runner.'],
    commonMistakes:['Not extending high enough — the defender blocks it.','Too much power — need soft touch.','Using this when inside hand finish is available — read the defense.'] },
  { id:'fn-14',name:'Pro Hop Finish',category:'Finishing',duration:8,difficulty:'intermediate',equipment:['ball','hoop'],type:'skill',
    summary:'A two-foot hop stop in the lane that creates space for a shot or pass.',
    steps:['Drive from the wing.','In the lane, pick up your dribble and hop forward landing on both feet.','You now have a pivot foot and can spin, shoot, or pass.','Finish with a power layup or short jumper.','10 reps from each side.'],
    coachingPoints:['The hop creates space between you and the defender.','Land on both feet at the same time — this is legal, not a travel.','After the hop, you\'re in a power position — use it.','You can pivot to either side after landing.'],
    commonMistakes:['Hopping too far — you end up under the basket.','Landing on one foot then the other — has to be simultaneous.','Not being balanced after landing.'] },
  { id:'fn-15',name:'Hop Step Finish',category:'Finishing',duration:8,difficulty:'intermediate',equipment:['ball','hoop'],type:'skill',
    summary:'Gather and take a big lateral hop step to avoid a shot blocker.',
    steps:['Drive down the lane from the top of the key.','As you approach the defender, take a big hop step to the side.','Finish with a short shot or layup from the new angle.','10 reps hopping right.','10 reps hopping left.'],
    coachingPoints:['The hop step is a legal gather move — pick up the ball and hop.','Land on both feet.','The hop gets you to a new angle where the defender can\'t block you.','Quick shot after the hop — don\'t hold the ball.'],
    commonMistakes:['Traveling — gather the ball before the hop.','Hopping into the defender instead of around them.','Holding the ball too long after landing.'] },
  { id:'fn-16',name:'Two Foot Finish',category:'Finishing',duration:6,difficulty:'beginner',equipment:['ball','hoop'],type:'skill',
    summary:'Jump off two feet for a strong, balanced finish at the rim.',
    steps:['Drive from the wing.','In the lane, plant both feet and jump straight up.','Finish with two hands — strong and balanced.','10 from each side.','Then add a pump fake before the two-foot finish.'],
    coachingPoints:['Two feet gives you more power and balance than one foot.','You can absorb contact better off two feet.','Pump fake, then two foot finish is deadly.','Land balanced in case you need to go up again for a putback.'],
    commonMistakes:['Jumping off one foot out of habit.','Not using the power advantage — finish STRONG.','Traveling — plant both feet cleanly.'] },
  { id:'fn-17',name:'One Foot Finish',category:'Finishing',duration:6,difficulty:'beginner',equipment:['ball','hoop'],type:'skill',
    summary:'Traditional layup finish off one foot — build speed and extension.',
    steps:['Drive from the right: jump off LEFT foot, finish RIGHT hand.','10 reps.','Drive from the left: jump off RIGHT foot, finish LEFT hand.','10 reps.','Then do the same but extend the ball as high as possible on the finish.'],
    coachingPoints:['Opposite foot, opposite hand — left foot up, right hand finish.','Drive your knee up — it generates lift.','Extend the ball up and forward toward the rim.','Soft off the backboard.'],
    commonMistakes:['Same foot same hand — use opposite.','Not driving the knee.','Not extending the ball up — finishing too low.'] },
  { id:'fn-18',name:'Up and Under Finish',category:'Finishing',duration:8,difficulty:'advanced',equipment:['ball','hoop'],type:'skill',
    summary:'Pump fake to get the defender in the air, then step through for an easy finish.',
    steps:['Start on the block with your back to the basket.','Catch the ball, pivot to face up.','Show a shot fake — get the defender in the air.','Step through (under their arm) and finish on the other side.','10 reps from right block, 10 from left block.'],
    coachingPoints:['The shot fake HAS to be convincing — show the ball above your head.','Wait for the defender to jump — be patient.','Step through quickly — one big step past them.','Finish with the hand away from the defender.'],
    commonMistakes:['Rushing the step-through before the defender jumps.','Weak shot fake.','Stepping into the defender instead of past them.'] },
  { id:'fn-19',name:'Putback Finishes',category:'Finishing',duration:8,difficulty:'intermediate',equipment:['ball','hoop'],type:'skill',
    summary:'Practice tipping and putting back missed shots off the glass.',
    steps:['Stand next to the rim.','Toss the ball off the backboard to simulate a missed shot.','Jump and grab the rebound at its highest point.','Immediately go back up and finish — no dribble, no bringing it down.','10 reps right side, 10 reps left side.','Then do it from further out — 3-4 feet from the basket.'],
    coachingPoints:['Go up STRONG — don\'t bring the ball down to your waist.','Chin the ball if you need to gather.','Quick second jump — be first off the floor.','This is a hustle play that wins games.'],
    commonMistakes:['Bringing the ball down — go right back up.','Pump faking after the rebound — just go up.','Not jumping a second time quickly enough.'] },
  { id:'fn-20',name:'Transition Layups',category:'Finishing',duration:8,difficulty:'beginner',equipment:['ball','hoop','full court'],type:'skill',
    summary:'Practice finishing in transition at full speed — the easiest points in basketball.',
    steps:['Start at the opposite baseline.','Push the ball full court at full speed.','Finish with a right hand layup.','Come back: left hand layup.','Then: euro step finish.','Then: floater.','Then: power layup.','2 reps of each finish (10 total trips).'],
    coachingPoints:['Transition layups should be automatic — these are free points.','Full speed the entire way. Don\'t slow down.','Use a different finish each trip to build your finishing repertoire.','In a game, you should NEVER miss a transition layup.'],
    commonMistakes:['Slowing down before the layup.','Same finish every time — practice variety.','Missing — these should be 100%.'] },
  { id:'fn-21',name:'Chair Finish Drill',category:'Finishing',duration:8,difficulty:'intermediate',equipment:['ball','hoop','chair'],type:'skill',
    summary:'Use a chair as a defender in the lane to practice finishing over and around obstacles.',
    steps:['Place a chair in the lane to simulate a shot blocker.','Drive from the wing and finish over/around the chair.','Use different finishes: floater over it, euro step around it, reverse past it.','5 reps of each finish from each side (30 total).'],
    coachingPoints:['The chair represents a big man in the lane — you have to adjust.','Read the "defender" — if they\'re in front, go around. If they\'re to the side, go over.','This is what finishing looks like in a real game — there\'s always someone there.'],
    commonMistakes:['Ignoring the chair and driving straight into it.','Same finish every time — use all your moves.','Not adjusting based on where the chair is.'] },
  { id:'fn-22',name:'Defender Pad Finishes',category:'Finishing',duration:8,difficulty:'advanced',equipment:['ball','hoop','blocking pad','partner'],type:'skill',
    summary:'Partner holds a pad and contests your finishes to simulate real game contact.',
    steps:['Partner stands in the lane with a blocking pad.','Drive from the wing.','Partner bumps you with the pad as you try to finish.','Absorb the contact and still make the shot.','10 from the right, 10 from the left.','Partner varies the contact — sometimes hard, sometimes light.'],
    coachingPoints:['Expect the contact — don\'t be surprised.','Keep your eyes on the rim THROUGH the contact.','Strong core and base absorb the hit.','Get the and-one — make the shot AND draw the foul.'],
    commonMistakes:['Closing eyes during contact.','Fading away from contact — go through it.','Losing the ball on the bump.'] },
  { id:'fn-23',name:'High Glass Finish',category:'Finishing',duration:6,difficulty:'beginner',equipment:['ball','hoop'],type:'skill',
    summary:'Aim high off the backboard to score over taller defenders.',
    steps:['Stand at the right block.','Shoot a layup aiming for the TOP of the backboard square.','The ball should hit high on the glass and drop in.','10 from right (right hand), 10 from left (left hand).','Then drive from the wing and practice high glass finishes at speed.'],
    coachingPoints:['Aiming high on the glass gets the ball over shot blockers.','Soft touch is critical — too hard and it bounces off.','This is especially useful for smaller players finishing over bigs.','The top corner of the square is your best friend.'],
    commonMistakes:['Aiming too low on the glass — go higher.','Too much power — soft touch.','Not using this in games — it\'s a real weapon.'] },
  { id:'fn-24',name:'Drop Step Finish',category:'Finishing',duration:8,difficulty:'intermediate',equipment:['ball','hoop'],type:'skill',
    summary:'Post move — catch on the block, drop step to the basket, and finish.',
    steps:['Start on the right block, back to the basket.','Catch a pass (toss to yourself).','Feel the defender on your back.','Drop step with your baseline foot — swing it toward the basket.','Finish with a power layup.','10 reps right block, 10 reps left block.'],
    coachingPoints:['The drop step is about feeling the defender\'s position.','If they\'re on your high side, drop step baseline.','Protect the ball — keep it chinned.','Finish strong off two feet.'],
    commonMistakes:['Telegraphing the drop step — keep the defense guessing.','Not protecting the ball — easy strip.','Soft finish after the drop step — be aggressive.'] },
  { id:'fn-25',name:'Post Move Finish',category:'Finishing',duration:10,difficulty:'advanced',equipment:['ball','hoop'],type:'skill',
    summary:'Develop a complete post move package: drop step, up-and-under, hook shot, fadeaway.',
    steps:['Right block: 5 drop step power layups.','Right block: 5 up-and-under moves.','Right block: 5 hook shots across the lane.','Right block: 5 fadeaway jumpers.','Repeat entire series from the left block.'],
    coachingPoints:['A complete post game makes you unguardable.','Read the defender to choose your move.','Each move should set up the next — show the hook, they jump, go up-and-under.','Footwork is everything in the post — slow your feet down and be precise.'],
    commonMistakes:['Always going to the same move.','Rushing the post moves — be patient.','Poor footwork — travels happen when feet are sloppy.'] },
  { id:'fn-26',name:'Weak Hand Finishing Series',category:'Finishing',duration:10,difficulty:'intermediate',equipment:['ball','hoop'],type:'skill',
    summary:'A complete weak hand finishing workout from every angle around the basket.',
    steps:['Weak hand only for the entire drill.','5 weak hand layups from the right side.','5 weak hand layups from the left side.','5 weak hand reverse layups from each side.','5 weak hand floaters from the lane.','5 weak hand power layups (jump off two feet).','5 weak hand euro step finishes.','5 weak hand finishes off one dribble from the wing.'],
    coachingPoints:['Your weak hand finishing is the difference between scoring and getting blocked when defenders take away your strong hand.','Use the backboard on every finish — the backboard is your friend with the weak hand.','Don\'t cheat by using your strong hand even once.','This is the drill that wins you a roster spot — coaches notice players who can finish both ways.'],
    commonMistakes:['Switching hands when it gets hard.','Soft touch — finish with authority.','Skipping reps because it feels uncomfortable.'] },
  { id:'fn-27',name:'Mid-Range Touch Drill',category:'Finishing',duration:8,difficulty:'intermediate',equipment:['ball','hoop'],type:'skill',
    summary:'Build soft touch on mid-range bank shots and short jumpers.',
    steps:['Start at the right elbow.','Shoot 10 mid-range bank shots — kiss the ball off the top corner of the backboard square.','Move to the left elbow. 10 more bank shots.','Then 10 short jumpers from each block (no backboard).','Then 10 from the free throw line, focusing on a soft swish — no rim contact.','Track your makes — the goal is 70%+ from mid-range.'],
    coachingPoints:['Touch is softer hands and a higher arc.','Mid-range bank shots from the elbow are nearly impossible to defend — every great mid-range scorer uses them.','Soft touch comes from your fingertips, not your palm.','High arc gives the ball more chances to drop in.'],
    commonMistakes:['Flat shots — get more arc.','Hard shots that bounce off — softer hands.','Only practicing threes and layups, ignoring mid-range — mid-range wins close games.'] },
];

// ============================================================
// DEFENSE (25 drills)
// ============================================================
const DEFENSE_DRILLS: Drill[] = [
  { id:'df-1',name:'Defensive Slide Drill',category:'Defense',duration:8,difficulty:'beginner',equipment:['court'],type:'skill',
    summary:'Build lateral quickness and defensive stance endurance.',
    steps:['Baseline in defensive stance.','Slide to free throw line and back.','Slide to half court and back.','Slide to far free throw line and back.','Slide full court and back.','3 reps, 30 seconds rest.'],
    coachingPoints:['Stay LOW.','Never cross feet.','Hands active and wide.','Head stays level.'],
    commonMistakes:['Standing up when tired.','Crossing feet.','Hands at sides.'] },
  { id:'df-2',name:'Closeout Drill',category:'Defense',duration:8,difficulty:'intermediate',equipment:['cones'],type:'skill',
    summary:'Sprint, chop, and contest shooters with proper closeout technique.',
    steps:['4 cones on the three-point line.','Start at rim.','Sprint to cone, chop feet near the end.','Hand up to contest. Don\'t jump.','Slide back. Sprint to next cone.','5 reps of all 4 cones.'],
    coachingPoints:['Sprint 80%, chop 20%.','Hand up but don\'t jump.','Angle body to force toward help.'],
    commonMistakes:['Flying past the cone.','Not getting hand up.','Jumping on closeout.'] },
  { id:'df-3',name:'Shell Drill',category:'Defense',duration:15,difficulty:'intermediate',equipment:['court','4 partners'],type:'skill',
    summary:'Team defensive drill — practice help side, rotations, and communication with 4 defenders.',
    steps:['4 offensive players around the three-point line. 4 defenders.','Offense passes the ball — NO dribbling.','Defense moves on every pass: on-ball pressure, deny, help side.','Rotate properly with every pass.','Play for 2 minutes, then switch offense/defense.'],
    coachingPoints:['Talk! Call out screens, ball, help.','See ball AND man at all times.','Jump to the ball on every pass — move when it moves.','Help side defenders should have one foot in the paint.'],
    commonMistakes:['Not talking — defense is 80% communication.','Ball-watching — losing your man.','Not jumping to the ball on the pass.'] },
  { id:'df-4',name:'Mirror Drill',category:'Defense',duration:6,difficulty:'intermediate',equipment:['partner'],type:'skill',
    summary:'Guard a partner one-on-one without the ball to build reaction time.',
    steps:['Face your partner at the free throw line.','They move randomly — lateral, forward, backward.','Mirror every move. Stay in front.','30 seconds on, 15 off. 6 rounds.'],
    coachingPoints:['Watch their hips, not feet.','React, don\'t guess.','Short choppy steps.','Weight on balls of feet.'],
    commonMistakes:['Watching feet.','Getting flat-footed.','Standing up.'] },
  { id:'df-5',name:'Zig-Zag Defensive Slides',category:'Defense',duration:5,difficulty:'beginner',equipment:['court'],type:'skill',
    summary:'Slide in a zigzag up the court simulating guarding a ball handler.',
    steps:['Baseline, left sideline.','Slide diagonally toward middle at 45 degrees.','After 4-5 slides, drop step and change direction.','Slide back toward sideline.','Zigzag to the other baseline. 3 full court trips.'],
    coachingPoints:['Low stance the entire time.','Drop step is the key move — don\'t cross feet.','Chest facing the direction you\'re sliding.','Faster each trip.'],
    commonMistakes:['Crossing feet during direction changes.','Standing up.','Not going fast enough.'] },
  { id:'df-6',name:'Charge Drill',category:'Defense',duration:8,difficulty:'intermediate',equipment:['court','partner'],type:'skill',
    summary:'Practice getting set and taking charges — the ultimate hustle play.',
    steps:['Stand in the paint with your heels outside the restricted area.','Partner drives from the wing.','Get your feet set, chest square to the driver, hands at your sides or on your chest.','Absorb the contact and fall backward safely.','Practice falling: tuck your chin, land on your butt, roll backward.','10 reps from each side.'],
    coachingPoints:['Feet MUST be set before contact — that\'s what makes it a charge, not a block.','Stay outside the restricted area under the basket.','Absorb the hit — don\'t lean into the driver.','Practice the safe fall — protect your head.'],
    commonMistakes:['Feet still moving on contact — that\'s a blocking foul.','Being in the restricted area.','Putting your hands out — keep them in.'] },
  { id:'df-7',name:'Box Out Drill',category:'Defense',duration:8,difficulty:'beginner',equipment:['court','partner','ball'],type:'skill',
    summary:'Secure rebounds by establishing position between your man and the basket.',
    steps:['Partner shoots from the free throw line.','When the shot goes up, find your man, make contact, pivot so your back is to them.','Hold the box out for 2 seconds — feel them behind you.','Then go get the rebound.','20 reps. Track how many rebounds you secure vs give up.'],
    coachingPoints:['Box out FIRST, then go get the ball.','Make contact — you need to feel where they are.','Wide base, low center of gravity. Be a wall.','Don\'t just watch the ball — find your man first.'],
    commonMistakes:['Ball-watching instead of boxing out.','No contact — you have to initiate the box out.','Going for the ball before establishing position.'] },
  { id:'df-8',name:'Rebound and Outlet Drill',category:'Defense',duration:8,difficulty:'intermediate',equipment:['ball','hoop','partner'],type:'skill',
    summary:'Grab the defensive rebound and immediately throw an outlet pass to start the fast break.',
    steps:['Partner shoots. You box out and rebound.','Immediately chin the ball (protect it).','Turn and throw a two-hand chest pass to your partner at the wing (outlet).','Sprint up the court after the pass.','20 reps. Focus on speed from rebound to outlet.'],
    coachingPoints:['Chin the ball — both hands, bring it to your chin.','The outlet should be a quick, accurate chest pass.','Hit the outlet on the same side you rebounded — don\'t swing it across.','The faster the outlet, the better chance at a fast break.'],
    commonMistakes:['Bringing the ball down low after rebounding — keep it high.','Slow outlet — has to be immediate.','Inaccurate outlet pass — hit your teammate in the chest.'] },
  { id:'df-9',name:'1 on 1 Full Court Defense',category:'Defense',duration:10,difficulty:'advanced',equipment:['court','partner','ball'],type:'skill',
    summary:'Guard someone the full length of the court — the ultimate defensive test.',
    steps:['Partner has the ball on the baseline.','Guard them as they try to dribble the full court.','Stay in front, don\'t reach — just contain them.','If they score, you go again. If you stop them, switch.','5 reps each as the defender.'],
    coachingPoints:['Don\'t reach — stay disciplined and slide.','Force them to their weak hand — push them one direction.','Stay a half-body length away — not too close, not too far.','Use your feet, not your hands. Hands cause fouls.'],
    commonMistakes:['Reaching and fouling.','Getting too close — they\'ll blow by you.','Giving up when beaten — recover!'] },
  { id:'df-10',name:'Deny the Wing Drill',category:'Defense',duration:8,difficulty:'intermediate',equipment:['cone','court'],type:'skill',
    summary:'Practice denying the pass to the wing — one pass away defense.',
    steps:['Cone at wing (offensive player). Cone at top of key (passer).','Deny position — hand in passing lane, seeing both cones.','React to cuts: if offense goes to the ball, stay in deny. If backdoor, drop and recover.','10 reps wing denial, 10 reps backdoor recovery.'],
    coachingPoints:['One hand in passing lane, one foot in paint.','See ball AND man.','Backdoor cut — open up and RUN.','Active hands — deflections win games.'],
    commonMistakes:['Turning back to ball.','Flat-footed on backdoor.','Arm dropping from passing lane.'] },
  { id:'df-11',name:'Help Side Defense Drill',category:'Defense',duration:8,difficulty:'advanced',equipment:['cones'],type:'skill',
    summary:'Practice rotating to help position and recovering to your man.',
    steps:['Cone at wing (your man) and cone at rim (help position).','Start guarding wing cone.','On cue, sprint to help position at the rim.','Touch cone, sprint back to wing cone.','Get low in stance immediately.','10 reps each side.'],
    coachingPoints:['See ball, see man — head on swivel.','Don\'t turn back to ball.','Recover at an angle.','Get LOW on arrival.'],
    commonMistakes:['Jogging back.','Turning back to ball.','Standing up on recovery.'] },
  { id:'df-12',name:'Defensive Stance Holds',category:'Defense',duration:5,difficulty:'beginner',equipment:[],type:'skill',
    summary:'Build leg endurance by holding a perfect defensive stance for extended periods.',
    steps:['Get in a perfect defensive stance: feet wider than shoulders, knees bent, butt low, hands up.','Hold for 30 seconds. Don\'t stand up.','Rest 15 seconds.','Hold for 45 seconds.','Rest 15 seconds.','Hold for 60 seconds.'],
    coachingPoints:['This is about building the leg strength to stay in your stance during a whole game.','If your thighs aren\'t burning, you\'re not low enough.','Keep your back straight — don\'t lean forward.','This is the foundation of all defense.'],
    commonMistakes:['Standing up before the time is done.','Knees caving inward — push them out.','Leaning forward — stay upright.'] },
  { id:'df-13',name:'Reaction Closeouts',category:'Defense',duration:8,difficulty:'advanced',equipment:['cones','partner'],type:'skill',
    summary:'Close out to a random spot called by a partner — builds reaction speed.',
    steps:['4 cones at different spots on the three-point line.','Start at the rim. Partner calls a number (1-4).','Sprint to that cone and closeout.','Partner immediately calls the next number.','Go for 30 seconds nonstop, rest 30. 5 rounds.'],
    coachingPoints:['React instantly — no hesitation.','Proper closeout technique every time, even under fatigue.','This simulates real game rotations where you\'re constantly moving.'],
    commonMistakes:['Anticipating instead of reacting.','Lazy closeouts when tired — stay disciplined.','Not chopping feet on the closeout.'] },
  { id:'df-14',name:'Ball Pressure Drill',category:'Defense',duration:8,difficulty:'intermediate',equipment:['partner','ball'],type:'skill',
    summary:'Practice applying tight on-ball pressure without fouling.',
    steps:['Partner has the ball at the top of key.','Get up close — one arm\'s length away.','Mirror their dribble with active hands — trace the ball.','Don\'t reach — just pressure with your stance and activity.','If they pick up their dribble, swarm them with hands up.','1 minute on, switch. 5 rounds each.'],
    coachingPoints:['Stay low and active — make them uncomfortable.','Don\'t reach — that\'s a foul. Use your body position.','When they pick up the dribble, that\'s your chance — get your hands in every passing lane.','Ball pressure creates turnovers for the whole team.'],
    commonMistakes:['Reaching and fouling.','Standing too far away — get in their space.','Not being active with hands — keep them moving.'] },
  { id:'df-15',name:'Trap Drill',category:'Defense',duration:8,difficulty:'advanced',equipment:['court','2 partners'],type:'skill',
    summary:'Practice trapping the ball handler with a teammate to force turnovers.',
    steps:['Ball handler at the wing. You and a partner are the trappers.','On a signal, both defenders sprint to the ball handler and trap.','Get your feet set. Don\'t foul. Hands high — take away the pass.','Ball handler tries to escape or pass out.','Rotate positions. 10 reps each role.'],
    coachingPoints:['The trap should be shoulder to shoulder — no gap between the two defenders.','Hands HIGH — you\'re taking away the vision and passing lanes.','Don\'t reach for the ball — the trap itself creates the turnover.','Anticipate where the offensive player wants to pass.'],
    commonMistakes:['Gap between trappers — the ball handler splits through.','Reaching and fouling.','Leaving your feet — stay grounded.'] },
  { id:'df-16',name:'Recover Drill',category:'Defense',duration:6,difficulty:'intermediate',equipment:['court'],type:'skill',
    summary:'Practice recovering after getting beat — the most important defensive skill.',
    steps:['Start in defensive stance at the wing.','Simulate getting beat: turn and sprint toward the basket.','Find the ball handler (imaginary), cut them off by getting in front.','Re-establish defensive stance.','10 reps from each side.'],
    coachingPoints:['Everyone gets beat. The great defenders RECOVER.','Sprint at an angle to cut off the driver — don\'t chase from behind.','The goal is to get in front and re-establish position.','Never give up on the play.'],
    commonMistakes:['Giving up after getting beat — always recover.','Chasing from behind instead of cutting off the angle.','Not getting back into a low stance after recovering.'] },
  { id:'df-17',name:'Defensive Shuffle Sprint Drill',category:'Defense',duration:5,difficulty:'intermediate',equipment:['court'],type:'skill',
    summary:'Alternate between defensive shuffles and sprints to simulate game transitions.',
    steps:['Start on baseline.','Defensive shuffle to free throw line.','Sprint to half court.','Defensive shuffle to far free throw line.','Sprint to far baseline.','Come back the same way. 3 reps.'],
    coachingPoints:['The transition from shuffle to sprint should be instant.','Stay low during the shuffles.','This simulates transitioning from half-court defense to sprinting back on a fast break.'],
    commonMistakes:['Pausing between shuffle and sprint.','Standing up during shuffles.','Slowing down when tired.'] },
  { id:'df-18',name:'Loose Ball Dive Drill',category:'Defense',duration:5,difficulty:'intermediate',equipment:['ball','court'],type:'skill',
    summary:'Practice diving on the floor for loose balls — pure hustle.',
    steps:['Partner rolls the ball across the floor.','Sprint to it and dive on it, securing it with both hands.','Practice the safe dive: slide on your stomach, chin up.','Get up quickly and make an outlet pass.','10 reps. Vary the direction the ball is rolled.'],
    coachingPoints:['Loose balls win games. Period.','Slide on your stomach/chest — don\'t land on your knees.','Secure the ball with both hands immediately.','Get up fast — the play isn\'t over.'],
    commonMistakes:['Not committing to the dive — go all out.','Landing on knees — ouch. Slide on your front.','Staying on the ground — get up and make a play.'] },
  { id:'df-19',name:'Contest Without Fouling Drill',category:'Defense',duration:8,difficulty:'intermediate',equipment:['partner','ball','hoop'],type:'skill',
    summary:'Practice contesting shots with verticality — straight up, no contact.',
    steps:['Partner catches the ball on the wing.','Close out and get hand up — STRAIGHT UP, not forward.','Partner shoots. You contest but don\'t touch them.','If you foul, that\'s a rep you owe: 2 push-ups.','20 reps. Track fouls vs clean contests.'],
    coachingPoints:['Go STRAIGHT UP — not forward into the shooter.','Verticality is your right — you can jump straight up in their space.','Contest with your closest hand — don\'t reach across.','The goal is to bother the shot without fouling.'],
    commonMistakes:['Lunging forward into the shooter — foul.','Jumping into the shooter\'s body — foul.','Not contesting at all — you have to get a hand up.'] },
  { id:'df-20',name:'Foot Fire Drill',category:'Defense',duration:3,difficulty:'beginner',equipment:[],type:'skill',
    summary:'Rapid foot movement in place to build quick feet for defense.',
    steps:['Defensive stance.','Chop your feet as fast as possible — tiny rapid steps.','On a command, drop to the floor and get back up.','Resume foot fire.','30 seconds of foot fire with 3-4 drops. Rest 15. 4 rounds.'],
    coachingPoints:['Feet should barely leave the ground — quick tiny steps.','Stay in your defensive stance — don\'t stand up.','The drops simulate diving for loose balls.','This builds the foot speed for staying in front of ball handlers.'],
    commonMistakes:['Feet coming up too high.','Standing up during foot fire.','Slow getting up from the drops.'] },
  { id:'df-21',name:'Lane Line Slides',category:'Defense',duration:5,difficulty:'beginner',equipment:['court'],type:'skill',
    summary:'Slide back and forth across the lane for defensive conditioning.',
    steps:['Left block in defensive stance.','Slide across the lane to right block.','Slide back. That\'s one rep.','15 reps as fast as possible.','Rest 30 seconds. 3 sets.'],
    coachingPoints:['Stay low.','Don\'t cross feet.','Touch the block each time.','Builds leg strength for game defense.'],
    commonMistakes:['Standing up.','Crossing feet.','Not touching blocks.'] },
  { id:'df-22',name:'Backpedal Sprint Drill',category:'Defense',duration:6,difficulty:'intermediate',equipment:['court'],type:'skill',
    summary:'Backpedal then turn and sprint — simulates getting back on defense in transition.',
    steps:['Start at baseline facing the court.','Backpedal to the free throw line.','At the free throw line, turn your hips and sprint to half court.','At half court, turn and backpedal to the far free throw line.','Sprint to the far baseline.','3 full court reps.'],
    coachingPoints:['The hip turn is the critical move — fast and smooth.','Backpedal on the balls of your feet, not heels.','This simulates getting back on defense: you backpedal first, then turn and sprint when you see the ball ahead of you.'],
    commonMistakes:['Slow hip turn — this is where you lose the race.','Backpedaling on heels — you\'ll trip.','Rounding the transition — sharp and quick.'] },
  { id:'df-23',name:'Defensive Mirror Slides',category:'Defense',duration:6,difficulty:'intermediate',equipment:['partner'],type:'skill',
    summary:'Mirror a partner\'s movements while maintaining perfect defensive form.',
    steps:['Face your partner, both in defensive stance, 6 feet apart.','Partner slides left and right, changes speed, stutters.','Mirror every movement — stay directly in front of them.','30 seconds. Switch who leads.','6 rounds total.'],
    coachingPoints:['Watch their midsection — it tells you where they\'re going.','Stay lower than them — lower man wins.','Quick reactions — move when they move, not after.'],
    commonMistakes:['Reacting late.','Standing up.','Crossing feet.'] },
  { id:'df-24',name:'Tip Drill',category:'Defense',duration:5,difficulty:'intermediate',equipment:['ball','hoop'],type:'skill',
    summary:'Practice tipping the ball to yourself on the backboard to build rebounding skills.',
    steps:['Stand near the rim.','Throw the ball off the backboard.','Jump and tip it back off the backboard with one hand.','Tip it 3-5 times in a row, then grab it and finish.','10 reps right hand only. 10 reps left hand only.'],
    coachingPoints:['Keep the ball alive on the glass — it\'s about timing your jumps.','Build the ability to tip and redirect the ball.','This helps with offensive rebounds in traffic.','Extend fully on each tip.'],
    commonMistakes:['Grabbing the ball too early — keep tipping.','Not jumping high enough to reach the ball.','Only using your strong hand — do both.'] },
  { id:'df-25',name:'Rebound War Drill',category:'Defense',duration:8,difficulty:'advanced',equipment:['ball','hoop','partner'],type:'skill',
    summary:'1-on-1 rebounding battle — fight for position and secure the board.',
    steps:['You and a partner stand in the lane, facing the basket.','A third person (or you toss it) shoots the ball.','Both of you fight for the rebound — box out, battle for position.','Whoever gets the rebound scores a point.','Play to 7 points.'],
    coachingPoints:['Make contact first — establish position before the ball comes off.','Wide base, low center of gravity.','Read the ball off the rim — long shots rebound long, short shots rebound short.','Want it more than they do.'],
    commonMistakes:['Not making contact — you have to box out.','Just watching the ball and hoping — fight for it.','Giving up on balls that bounce away — chase every rebound.'] },
];

// ============================================================
// SPEED & AGILITY (25 drills)
// ============================================================
const SPEED_AGILITY_DRILLS: Drill[] = [
  { id:'sa-1',name:'Ladder Quick Feet',category:'Speed & Agility',duration:5,difficulty:'beginner',equipment:['agility ladder'],type:'conditioning',
    summary:'Run through a ladder with quick, precise foot placement to build foot speed.',
    steps:['Lay the ladder flat on the ground.','Run through stepping one foot in each square — as fast as possible.','Walk back. Run through again: two feet in each square.','Walk back. Run through with lateral steps (facing sideways).','4 patterns, 3 reps each.'],
    coachingPoints:['Quick feet, not high feet — keep them low and fast.','Don\'t look at the ladder — use your peripheral vision.','Pump your arms — they drive your foot speed.','Accuracy first, then add speed.'],
    commonMistakes:['Stepping on the rungs — be precise.','Going too slow — push yourself.','Not pumping arms.'] },
  { id:'sa-2',name:'Ladder In and Outs',category:'Speed & Agility',duration:5,difficulty:'beginner',equipment:['agility ladder'],type:'conditioning',
    summary:'Step in and out of each ladder square laterally — builds lateral quickness.',
    steps:['Stand beside the ladder.','Step IN with both feet (one at a time) to the first square.','Step OUT with both feet to the other side.','Step IN to the next square. Step OUT.','Move down the entire ladder.','3 reps each direction.'],
    coachingPoints:['Stay on the balls of your feet.','Keep your hips low.','Quick, rhythmic movements — find a cadence.','This directly translates to defensive slides.'],
    commonMistakes:['Flat-footed — stay on toes.','Standing up — stay low.','Going too slow — push the pace.'] },
  { id:'sa-3',name:'Ladder Icky Shuffle',category:'Speed & Agility',duration:5,difficulty:'intermediate',equipment:['agility ladder'],type:'conditioning',
    summary:'The classic Icky Shuffle — in-in-out pattern through the ladder.',
    steps:['Start beside the ladder.','Step IN with your lead foot, then IN with your other foot.','Step OUT to the other side with your lead foot.','Step IN with trailing foot to the next square.','Continue the in-in-out pattern down the ladder.','3 reps each direction.'],
    coachingPoints:['The pattern is: in-in-out, in-in-out.','Start slow to learn the pattern, then speed up.','This is one of the best agility drills for basketball players.','Keep your core engaged and arms pumping.'],
    commonMistakes:['Getting confused on the pattern — slow down.','Stepping on the rungs.','Not going fast enough once you know the pattern.'] },
  { id:'sa-4',name:'Cone Shuttle Drill',category:'Speed & Agility',duration:5,difficulty:'beginner',equipment:['cones'],type:'conditioning',
    summary:'Sprint between two cones to build acceleration and deceleration.',
    steps:['Place two cones 15 feet apart.','Sprint from cone 1 to cone 2. Touch it.','Sprint back to cone 1. Touch it.','That\'s one rep. Do 10 reps.','Rest 30 seconds. 3 sets.'],
    coachingPoints:['The turn is the drill — decelerate and change direction as fast as possible.','Stay low on the turns.','Push off hard with the outside foot.','Full speed both ways.'],
    commonMistakes:['Rounding the turns — plant and cut.','Coasting into the cone.','Not touching the cone — discipline.'] },
  { id:'sa-5',name:'5-10-5 Shuttle Run',category:'Speed & Agility',duration:5,difficulty:'intermediate',equipment:['cones'],type:'conditioning',
    summary:'The NFL combine shuttle test — 5 yards, 10 yards, 5 yards for explosive changes of direction.',
    steps:['Place 3 cones 5 yards apart in a line.','Start at the middle cone in a three-point stance.','Sprint 5 yards to the right cone. Touch it.','Sprint 10 yards to the left cone. Touch it.','Sprint 5 yards back to the middle.','5 reps. Track your time.'],
    coachingPoints:['Low center of gravity on every turn.','Plant hard with your outside foot to change direction.','The start and the turns are where you win or lose time.','This measures your change-of-direction speed.'],
    commonMistakes:['Standing up during turns.','Wide turns instead of sharp cuts.','Not going 100% effort.'] },
  { id:'sa-6',name:'Suicide Runs',category:'Speed & Agility',duration:5,difficulty:'beginner',equipment:['court'],type:'conditioning',
    summary:'Sprint to each line and back — classic basketball conditioning.',
    steps:['Baseline to free throw line and back.','Baseline to half court and back.','Baseline to far free throw line and back.','Baseline to far baseline and back.','Rest 30 seconds. 4 total.'],
    coachingPoints:['Touch each line.','Sharp direction changes.','Stay low changing direction.','Push hard on the last two.'],
    commonMistakes:['Not touching lines.','Slowing on return.','Rounding turns.'] },
  { id:'sa-7',name:'Cone Zig-Zag Sprint',category:'Speed & Agility',duration:6,difficulty:'intermediate',equipment:['cones'],type:'conditioning',
    summary:'Sprint through cones in a zigzag — builds change of direction at full speed.',
    steps:['Set up 8 cones in a zigzag pattern, 8 feet apart.','Sprint to the first cone, sharp cut to the next.','Continue zigzagging through all cones.','Walk back and go again.','5 reps. Try to beat your time.'],
    coachingPoints:['Plant your outside foot hard on each cut.','Don\'t round the turns — sharp angles.','Lean into each cut.','Pump your arms through the turns.'],
    commonMistakes:['Rounding the corners.','Slowing down before the cuts.','Not leaning into the change of direction.'] },
  { id:'sa-8',name:'Defensive Slide Sprints',category:'Speed & Agility',duration:6,difficulty:'intermediate',equipment:['court'],type:'conditioning',
    summary:'Alternate defensive slides and sprints to simulate game defensive transitions.',
    steps:['Defensive slide baseline to free throw line.','Sprint to half court.','Slide to far free throw line.','Sprint to far baseline.','3 full court trips.'],
    coachingPoints:['Instant transition between slide and sprint.','Stay low during slides.','Simulates transitioning between half-court D and sprinting back.'],
    commonMistakes:['Pausing between slide and sprint.','Standing up during slides.'] },
  { id:'sa-9',name:'Backpedal Sprint Drill',category:'Speed & Agility',duration:6,difficulty:'beginner',equipment:['court'],type:'conditioning',
    summary:'Backpedal then sprint forward — builds transition defense speed.',
    steps:['Baseline facing the court.','Backpedal to free throw line.','Turn hips and sprint to half court.','Backpedal to far free throw line.','Sprint to far baseline.','3 reps.'],
    coachingPoints:['Fast hip turn.','Backpedal on balls of feet.','Simulates getting back on defense.'],
    commonMistakes:['Slow hip turn.','Backpedaling on heels.','Rounding transitions.'] },
  { id:'sa-10',name:'Lateral Cone Hops',category:'Speed & Agility',duration:5,difficulty:'intermediate',equipment:['cone'],type:'conditioning',
    summary:'Hop laterally over a cone to build explosive side-to-side power.',
    steps:['Place one cone on the ground.','Stand to the left of it.','Jump laterally over the cone, landing on both feet on the other side.','Immediately jump back.','30 seconds of continuous hopping. Rest 15. 5 rounds.'],
    coachingPoints:['Quick ground contact — spend as little time on the ground as possible.','Stay on the balls of your feet.','Keep your core tight for balance.','This builds the explosive lateral movement needed for defense.'],
    commonMistakes:['Spending too long on the ground between hops.','Landing on heels.','Losing balance — stay tight.'] },
  { id:'sa-11',name:'Single Leg Bounds',category:'Speed & Agility',duration:5,difficulty:'intermediate',equipment:['flat surface'],type:'conditioning',
    summary:'Explosive single-leg jumps forward for power and balance.',
    steps:['Stand on your right foot.','Bound forward as far as you can, landing on your right foot.','Stick the landing for 1 second.','Bound again. 5 bounds on right foot.','Switch to left foot. 5 bounds.','3 rounds.'],
    coachingPoints:['Swing your arms to generate power.','Land softly on the ball of your foot.','Stick each landing — if you wobble, it doesn\'t count.','This builds single-leg power for driving and finishing.'],
    commonMistakes:['Not sticking the landing.','Short bounds — push for distance.','Landing flat-footed.'] },
  { id:'sa-12',name:'Broad Jumps',category:'Speed & Agility',duration:5,difficulty:'beginner',equipment:['flat surface'],type:'conditioning',
    summary:'Standing broad jumps for explosive horizontal power.',
    steps:['Stand with feet shoulder width, toes at a line.','Bend your knees, swing your arms back.','Explode forward, jumping as far as you can.','Land on both feet. Stick it.','Mark your distance. Try to beat it.','10 jumps with 15 seconds rest between.'],
    coachingPoints:['Arms generate power — swing them hard.','Triple extension: ankles, knees, hips all fire at once.','Land with soft knees.','This is raw explosive power — give 100% every jump.'],
    commonMistakes:['Not using arms.','Landing with stiff legs.','Not fully extending on the jump.'] },
  { id:'sa-13',name:'Sprint and Backpedal',category:'Speed & Agility',duration:6,difficulty:'beginner',equipment:['court'],type:'conditioning',
    summary:'Alternate sprinting and backpedaling to build transition speed.',
    steps:['Sprint to free throw line. Backpedal to baseline.','Sprint to half court. Backpedal to baseline.','Sprint to far free throw line. Backpedal to baseline.','Sprint full court.','Rest 45 seconds. 3 reps.'],
    coachingPoints:['Instant transition between sprint and backpedal.','Stay low on direction changes.','Balls of feet on backpedal.'],
    commonMistakes:['Pausing between sprint and backpedal.','Backpedaling on heels.','Slowing at longer distances.'] },
  { id:'sa-14',name:'Reaction Sprint Drill',category:'Speed & Agility',duration:6,difficulty:'intermediate',equipment:['partner'],type:'conditioning',
    summary:'Sprint on a random command to build reaction time and first-step quickness.',
    steps:['Stand in athletic stance. Partner behind you.','Partner claps or yells "GO" at random times.','Sprint 10 yards as fast as you can.','Walk back. Wait for the next signal.','10 reps. Focus on your first step explosion.'],
    coachingPoints:['Stay ready — weight on the balls of your feet.','The first step is everything — explode.','Don\'t anticipate — react to the actual signal.','This builds the reaction time you need on the court.'],
    commonMistakes:['Anticipating the signal — wait for it.','Slow first step — explode off the line.','Standing flat-footed while waiting.'] },
  { id:'sa-15',name:'T Drill',category:'Speed & Agility',duration:5,difficulty:'intermediate',equipment:['cones'],type:'conditioning',
    summary:'Sprint, shuffle, and backpedal in a T pattern for total agility.',
    steps:['Set up cones in T shape.','Sprint to middle cone.','Shuffle left to left cone.','Shuffle right to right cone.','Shuffle back to middle.','Backpedal to start.','5 reps, beat your time.'],
    coachingPoints:['Stay low through every direction change.','Don\'t cross feet shuffling.','Push off outside foot.','Head and eyes up.'],
    commonMistakes:['Standing up.','Crossing feet.','Rounding corners.'] },
  { id:'sa-16',name:'Box Drill',category:'Speed & Agility',duration:5,difficulty:'intermediate',equipment:['cones'],type:'conditioning',
    summary:'Sprint, shuffle, backpedal, and shuffle in a box pattern — covers all movement planes.',
    steps:['4 cones in a 10-yard square.','Sprint forward to cone 2.','Shuffle right to cone 3.','Backpedal to cone 4.','Shuffle left back to start.','5 reps clockwise, 5 counterclockwise.'],
    coachingPoints:['Sharp transitions at each cone.','Stay low the entire time.','This covers every movement direction in basketball.','Vary which direction you go each rep.'],
    commonMistakes:['Rounding the corners.','Slow transitions between movement types.','Only going one direction.'] },
  { id:'sa-17',name:'Line Hops',category:'Speed & Agility',duration:3,difficulty:'beginner',equipment:['court line'],type:'conditioning',
    summary:'Quick hops over a line to build foot speed and coordination.',
    steps:['Stand next to any court line.','Hop side to side over the line — both feet together.','30 seconds as fast as you can.','Rest 15.','Then do front to back hops over the line.','Then single foot hops (right only, then left only).','3 rounds of each pattern.'],
    coachingPoints:['Minimum ground contact time.','Stay on your toes — never let your heels touch.','Small, quick hops — not big jumps.','This builds the foot speed for basketball.'],
    commonMistakes:['Too much time on the ground.','Heels touching.','Jumping too high — stay low and quick.'] },
  { id:'sa-18',name:'Carioca Drill',category:'Speed & Agility',duration:5,difficulty:'beginner',equipment:['court'],type:'conditioning',
    summary:'Lateral grapevine movement to build hip mobility and coordination.',
    steps:['Face the sideline.','Cross your right foot in FRONT of your left.','Step your left foot to the left.','Cross your right foot BEHIND your left.','Continue this front-behind pattern down the court.','3 reps each direction.'],
    coachingPoints:['Open your hips on each crossover step.','Stay light on your feet.','Arms should be active for balance.','This builds the hip mobility needed for defensive slides.'],
    commonMistakes:['Moving too slowly — build speed.','Not crossing far enough — full range of motion.','Upper body twisting too much — keep chest forward.'] },
  { id:'sa-19',name:'Sprint Turn Sprint',category:'Speed & Agility',duration:5,difficulty:'intermediate',equipment:['court'],type:'conditioning',
    summary:'Sprint, make a sharp 180-degree turn, and sprint back — builds deceleration and acceleration.',
    steps:['Sprint from baseline to the free throw line.','Make a sharp 180-degree turn (plant and spin).','Sprint back to the baseline.','10 reps. Try to minimize the time spent turning.'],
    coachingPoints:['The turn should be a sharp plant-and-go, not a wide loop.','Decelerate in 2-3 steps — don\'t coast to a stop.','Explode out of the turn — that\'s where you save time.','Drop your hips low during the turn for balance.'],
    commonMistakes:['Wide arcing turn instead of a sharp plant.','Not decelerating — you\'ll slip.','Slow acceleration out of the turn.'] },
  { id:'sa-20',name:'Resistance Band Sprints',category:'Speed & Agility',duration:8,difficulty:'intermediate',equipment:['resistance band','partner'],type:'conditioning',
    summary:'Sprint against resistance to build explosive acceleration power.',
    steps:['Put a resistance band around your waist. Partner holds the other end.','Sprint 10-15 yards against the resistance.','Walk back. Go again.','10 resisted sprints.','Then remove the band and do 5 free sprints — you\'ll feel faster.'],
    coachingPoints:['Lean forward against the resistance — drive your knees.','The resistance teaches proper sprint mechanics.','The free sprints after feel amazing — like you\'re flying.','This is how NFL players train for speed.'],
    commonMistakes:['Standing too upright — lean into it.','Not driving knees high enough.','Skipping the free sprints after — that\'s the best part.'] },
  { id:'sa-21',name:'Partner Reaction Drill',category:'Speed & Agility',duration:6,difficulty:'intermediate',equipment:['partner'],type:'conditioning',
    summary:'React to a partner\'s visual cues to build game-speed decision making.',
    steps:['Face your partner 5 yards apart.','Partner points left, right, or up randomly.','Left = shuffle left. Right = shuffle right. Up = sprint to them.','React instantly and return to start.','30 seconds on. Rest 15. 6 rounds.'],
    coachingPoints:['React to the signal, don\'t anticipate.','First step should be explosive.','Stay in your athletic stance between signals.','This trains your brain and body to react at game speed.'],
    commonMistakes:['Guessing instead of reacting.','Slow first step.','Standing up between signals.'] },
  { id:'sa-22',name:'Quick Drop Step Drill',category:'Speed & Agility',duration:5,difficulty:'intermediate',equipment:['court'],type:'conditioning',
    summary:'Practice the drop step — pivoting your hips quickly to change direction.',
    steps:['Start in defensive stance.','Drop step to the right — swing your right foot back and sprint right.','3 steps, then drop step to the left.','Continue down the court alternating drop steps.','3 full court trips.'],
    coachingPoints:['The drop step is how you change direction without crossing your feet.','Swing the foot wide to open your hips.','This is the key move in 1-on-1 defense.','Quick hips win defensive battles.'],
    commonMistakes:['Crossing your feet instead of drop stepping.','Not opening hips enough.','Slow pivot.'] },
  { id:'sa-23',name:'Shuffle Sprint Shuffle',category:'Speed & Agility',duration:5,difficulty:'intermediate',equipment:['court'],type:'conditioning',
    summary:'Defensive shuffle into a sprint into a shuffle — game-realistic transitions.',
    steps:['Start at the sideline in defensive stance.','Shuffle to the lane line.','Sprint to half court.','Shuffle to the far lane line.','Sprint to the far sideline.','3 reps. Rest 30 seconds between.'],
    coachingPoints:['Transitions should be seamless — no pause.','Stay low during shuffles.','Full speed on sprints.','This is exactly what you do in a game — guard, sprint back, guard again.'],
    commonMistakes:['Pausing between movements.','Standing up during shuffles.','Not sprinting at full speed.'] },
  { id:'sa-24',name:'Jump Stop Sprint Drill',category:'Speed & Agility',duration:5,difficulty:'beginner',equipment:['court'],type:'conditioning',
    summary:'Practice the jump stop followed by an explosive sprint — essential basketball movement.',
    steps:['Jog forward.','On command (or every 5 steps), perform a jump stop — land on both feet, low and balanced.','Immediately explode into a sprint for 5 yards.','Jog, jump stop, sprint. Repeat down the court.','3 full court trips.'],
    coachingPoints:['The jump stop should be sudden and balanced.','Land with feet shoulder width, knees bent.','The sprint after should be instant — no hesitation.','This trains the stop-and-go that basketball demands.'],
    commonMistakes:['Landing off-balance on the jump stop.','Slow transition from stop to sprint.','Jump stop landing on one foot — needs to be two feet.'] },
  { id:'sa-25',name:'Acceleration Sprints',category:'Speed & Agility',duration:5,difficulty:'beginner',equipment:['court'],type:'conditioning',
    summary:'Practice going from zero to full speed as fast as possible — first step quickness.',
    steps:['Stand completely still on the baseline.','On command, explode to full speed as fast as you can.','Sprint 10 yards, then coast.','Walk back. Reset.','10 reps. Focus on the first 3 steps.'],
    coachingPoints:['The first 3 steps are everything — that\'s where basketball is won.','Lean forward, drive your arms, push off hard.','Low body angle at the start — like a sprinter out of the blocks.','10 yards is all you need in basketball — it\'s not a track race.'],
    commonMistakes:['Standing upright at the start — lean forward.','Not driving arms.','Jogging the first few steps — EXPLODE.'] },
];

// ============================================================
// WARMUP & COOLDOWN (25 drills)
// ============================================================
const WARMUP_DRILLS: Drill[] = [
  { id:'wu-1',name:'High Knees',category:'Warmup & Cooldown',duration:2,difficulty:'beginner',equipment:[],type:'warmup',
    summary:'Drive your knees up rapidly while jogging to activate hip flexors and build coordination.',
    steps:['Jog in place or forward slowly.','Drive each knee up to hip height as quickly as you can.','Pump your arms in rhythm with your knees.','30 seconds on, 15 off. 3 rounds.'],
    coachingPoints:['Quick ground contact — pop off the ground.','Arms pump opposite to legs.','Stay on balls of your feet.'],
    commonMistakes:['Knees not coming high enough.','Leaning backward.','Flat-footed.'] },
  { id:'wu-2',name:'Butt Kicks',category:'Warmup & Cooldown',duration:2,difficulty:'beginner',equipment:[],type:'warmup',
    summary:'Kick your heels to your glutes while jogging to activate hamstrings.',
    steps:['Jog forward slowly.','Kick each heel up toward your butt.','Quick rhythmic kicks — like running but kicking back.','30 seconds. 3 rounds.'],
    coachingPoints:['Quick turnover — feet move fast.','Stay upright.','This activates your hamstrings for sprinting.'],
    commonMistakes:['Leaning forward too much.','Slow kicks.','Not reaching your butt.'] },
  { id:'wu-3',name:'Walking Lunges',category:'Warmup & Cooldown',duration:3,difficulty:'beginner',equipment:[],type:'warmup',
    summary:'Dynamic lunge to stretch hips, quads, and glutes while building stability.',
    steps:['Step forward with your right leg into a deep lunge.','Back knee nearly touches the ground.','Push off and step through to lunge with the left leg.','Continue walking forward for 10 each leg.','Add a twist — rotate your torso toward the front knee.'],
    coachingPoints:['Front knee stays over your ankle — don\'t let it drift forward over your toes.','Keep your chest up and core tight.','Go deep — get a full range of motion.'],
    commonMistakes:['Knee going past toes.','Leaning forward.','Short, shallow lunges.'] },
  { id:'wu-4',name:'Leg Swings',category:'Warmup & Cooldown',duration:2,difficulty:'beginner',equipment:[],type:'warmup',
    summary:'Swing your legs front-to-back and side-to-side to loosen hips.',
    steps:['Hold a wall or pole for balance.','Swing your right leg forward and backward — 10 times, increasing range.','Swing your right leg side to side across your body — 10 times.','Switch to left leg. Same pattern.'],
    coachingPoints:['Let gravity do the work — don\'t force it.','Gradually increase the range of each swing.','This opens up your hips for cutting and defensive slides.'],
    commonMistakes:['Forcing the range — let it build naturally.','Losing balance — hold something.','Skipping side-to-side swings.'] },
  { id:'wu-5',name:'Arm Circles',category:'Warmup & Cooldown',duration:2,difficulty:'beginner',equipment:[],type:'warmup',
    summary:'Warm up shoulders with progressively larger arm circles.',
    steps:['Extend both arms straight out to the sides.','Make small forward circles for 15 reps.','Gradually increase to large circles for 15 reps.','Reverse: large backward circles for 15 reps.','Small backward circles for 15 reps.'],
    coachingPoints:['Start small and build to larger circles.','Keep your core engaged — don\'t arch your back.','This prevents shoulder injuries during shooting and passing.'],
    commonMistakes:['Starting with large circles — build up.','Rushing through it.'] },
  { id:'wu-6',name:'Hip Openers',category:'Warmup & Cooldown',duration:3,difficulty:'beginner',equipment:[],type:'warmup',
    summary:'Open up your hip joints with high knee rotations.',
    steps:['Stand tall. Lift your right knee to hip height.','Rotate it outward in a circle — like stepping over a hurdle.','10 reps with right leg.','10 reps with left leg.','Then do 10 reps rotating inward each leg.'],
    coachingPoints:['Controlled circles — don\'t just fling your leg.','This activates the muscles you use for lateral movement.','Tight hips = slow defender. Open hips = quick defender.'],
    commonMistakes:['Circles too small — open up.','Losing balance — engage your core.','Rushing.'] },
  { id:'wu-7',name:'Hamstring Stretch',category:'Warmup & Cooldown',duration:3,difficulty:'beginner',equipment:[],type:'warmup',
    summary:'Dynamic hamstring stretch to prevent pulls and strains.',
    steps:['Stand tall. Kick your right leg straight up, reaching for your toes.','Keep the leg straight. Don\'t force it — go as high as comfortable.','10 kicks each leg.','Then: put your right heel on a ledge or chair. Lean forward with a flat back.','Hold for 20 seconds each side.'],
    coachingPoints:['Keep your back flat when leaning into the stretch.','Don\'t bounce — smooth, controlled movement.','Hamstring injuries are the most common in basketball — don\'t skip this.'],
    commonMistakes:['Rounding your back — keep it flat.','Bouncing into the stretch.','Not holding long enough.'] },
  { id:'wu-8',name:'Quad Stretch',category:'Warmup & Cooldown',duration:2,difficulty:'beginner',equipment:[],type:'warmup',
    summary:'Stretch your quadriceps to prepare for jumping and sprinting.',
    steps:['Stand on your left foot.','Grab your right ankle behind you and pull it toward your glute.','Hold for 20 seconds.','Switch legs. Hold for 20 seconds.','Do 2 rounds each side.'],
    coachingPoints:['Keep your knees together — don\'t let the stretching knee flare out.','Stand tall — don\'t lean forward.','You should feel the stretch in the front of your thigh.'],
    commonMistakes:['Knee flaring out to the side.','Leaning forward or arching back.','Holding your foot instead of your ankle.'] },
  { id:'wu-9',name:'Calf Stretch',category:'Warmup & Cooldown',duration:2,difficulty:'beginner',equipment:['wall'],type:'warmup',
    summary:'Stretch your calves to prevent tightness and Achilles injuries.',
    steps:['Face a wall. Put your hands on it.','Step your right foot back about 2-3 feet.','Keep your right heel on the ground and lean forward.','Hold for 20 seconds. Switch legs.','Then bend the back knee slightly to stretch the lower calf.','Hold for 20 seconds each side.'],
    coachingPoints:['Keep the back heel down — that\'s what creates the stretch.','Straight leg stretches the upper calf. Bent knee stretches the lower.','Basketball players are notorious for calf and Achilles injuries — this prevents them.'],
    commonMistakes:['Back heel coming up — keep it planted.','Not holding long enough.','Skipping the bent-knee variation.'] },
  { id:'wu-10',name:'Groin Stretch',category:'Warmup & Cooldown',duration:3,difficulty:'beginner',equipment:[],type:'warmup',
    summary:'Open up the groin and inner thigh to prevent strains during lateral movement.',
    steps:['Stand with feet wide — wider than shoulder width.','Shift your weight to the right, bending your right knee.','Left leg stays straight. You\'ll feel the stretch in your left inner thigh.','Hold for 15 seconds. Shift to the other side.','3 rounds each side.','Then: sit on the ground, soles of your feet together, push knees toward the floor.'],
    coachingPoints:['Basketball demands a lot of lateral movement — your groin needs to be ready.','Don\'t force the stretch — go to where you feel it, not where it hurts.','A groin pull can sideline you for weeks — this 3-minute stretch prevents it.'],
    commonMistakes:['Forcing too deep too fast.','Bouncing in the stretch.','Skipping this entirely.'] },
  { id:'wu-11',name:'Ankle Mobility Drill',category:'Warmup & Cooldown',duration:3,difficulty:'beginner',equipment:[],type:'warmup',
    summary:'Improve ankle flexibility to prevent sprains — the most common basketball injury.',
    steps:['Stand facing a wall, one foot a few inches from it.','Bend your knee and try to touch the wall with your knee while keeping your heel down.','10 reps each foot.','Then: draw the alphabet in the air with each foot — this moves your ankle through every range of motion.'],
    coachingPoints:['Ankle sprains are the #1 basketball injury. This drill prevents them.','If you can\'t touch the wall, that means your ankle mobility needs work.','The alphabet drill sounds silly but it\'s incredibly effective.'],
    commonMistakes:['Heel coming off the ground.','Rushing through the alphabet — actually draw each letter.','Only doing this after an injury — do it BEFORE.'] },
  { id:'wu-12',name:'Dynamic Toe Touch',category:'Warmup & Cooldown',duration:2,difficulty:'beginner',equipment:[],type:'warmup',
    summary:'Walking toe touches to warm up hamstrings and lower back.',
    steps:['Walk forward. Kick your right leg up straight.','Reach for your right toes with your left hand.','Step and kick your left leg up. Reach with your right hand.','Continue walking and kicking for 10 each leg.'],
    coachingPoints:['Don\'t force the range — go as high as comfortable.','Keep the kicking leg straight.','This warms up your hamstrings dynamically — better than static stretching before playing.'],
    commonMistakes:['Bending the kicking leg.','Leaning way forward — stay upright.','Going too fast.'] },
  { id:'wu-13',name:'Side Lunges',category:'Warmup & Cooldown',duration:3,difficulty:'beginner',equipment:[],type:'warmup',
    summary:'Lateral lunges to warm up your groin and prepare for defensive slides.',
    steps:['Stand with feet together.','Step wide to the right into a side lunge — right knee bends, left leg stays straight.','Push off and return to center.','Step to the left into a side lunge.','10 each direction.'],
    coachingPoints:['Knee stays over your ankle — don\'t let it cave in.','Push your hips back as you lunge.','This directly prepares you for defensive movement.'],
    commonMistakes:['Knee caving inward.','Not going low enough.','Leaning forward instead of sitting back.'] },
  { id:'wu-14',name:'Jump Rope Warmup',category:'Warmup & Cooldown',duration:5,difficulty:'beginner',equipment:['jump rope'],type:'warmup',
    summary:'5 minutes of jump rope to elevate your heart rate and warm up your whole body.',
    steps:['Regular two-foot bounce for 1 minute.','Alternate feet (running in place) for 1 minute.','Side to side hops for 1 minute.','Double unders or high knees for 1 minute.','Regular bounce cooldown for 1 minute.'],
    coachingPoints:['Jump rope is one of the best basketball warmups — it builds footwork, timing, and conditioning.','Stay on the balls of your feet.','Wrists do the work, not your arms.','If you don\'t have a rope, just jump in place mimicking the motion.'],
    commonMistakes:['Using your whole arms to spin — use wrists.','Jumping too high — small, efficient hops.','Getting frustrated when you trip — keep going.'] },
  { id:'wu-15',name:'Light Form Shooting Warmup',category:'Warmup & Cooldown',duration:5,difficulty:'beginner',equipment:['ball','hoop'],type:'warmup',
    summary:'Gradually build into your shooting with close-range form work.',
    steps:['10 form shots from 3 feet.','10 from 5 feet.','10 from 8 feet.','10 from free throw line.','5 from each elbow.'],
    coachingPoints:['Build your feel for the day.','Perfect form on every shot.','If it feels off, stay close and fix before moving out.'],
    commonMistakes:['Skipping straight to threes.','Rushing.'] },
  { id:'wu-16',name:'Jog and Backpedal',category:'Warmup & Cooldown',duration:3,difficulty:'beginner',equipment:['court'],type:'warmup',
    summary:'Light jog forward and backward to gradually raise your heart rate.',
    steps:['Jog from baseline to free throw line.','Backpedal to baseline.','Jog to half court. Backpedal to baseline.','Jog full court. Backpedal full court.','2 rounds. Easy pace.'],
    coachingPoints:['This is a warmup, not a sprint.','Gradually increase speed with each round.','Backpedal on your toes.'],
    commonMistakes:['Going too fast — this is a warmup.','Skipping this to save time — you\'ll regret it.'] },
  { id:'wu-17',name:'Defensive Slides Warmup',category:'Warmup & Cooldown',duration:3,difficulty:'beginner',equipment:['court'],type:'warmup',
    summary:'Light defensive slides to prepare your legs for lateral movement.',
    steps:['Defensive stance. Slide from sideline to sideline.','Go at 50% speed. Focus on form.','5 trips across.','Then slide from baseline to free throw line and back.','3 trips. Keep it light.'],
    coachingPoints:['This is NOT a conditioning drill — keep it light.','Focus on proper form: low stance, no crossing feet, hands up.','You\'re getting your legs ready for the real work.'],
    commonMistakes:['Going too hard — save your energy.','Crossing your feet — even at a light pace, maintain proper form.'] },
  { id:'wu-18',name:'Foam Rolling',category:'Warmup & Cooldown',duration:5,difficulty:'beginner',equipment:['foam roller'],type:'warmup',
    summary:'Roll out tight muscles before and after training to prevent injury and improve mobility.',
    steps:['Quads: lie face down and roll from hip to knee. 30 seconds each leg.','Hamstrings: sit on the roller and roll from hip to knee. 30 seconds each.','IT band: lie on your side and roll from hip to knee. 30 seconds each.','Calves: sit with calves on the roller. Roll ankle to knee. 30 seconds each.','Back: lie on the roller and roll from mid-back to upper back. 30 seconds.'],
    coachingPoints:['When you hit a sore spot, stop and hold for 10 seconds — let it release.','Don\'t roll over joints — only on muscles.','This is one of the best recovery tools you can use.','Do this before AND after workouts.'],
    commonMistakes:['Rolling too fast — slow, controlled movements.','Rolling over your knees — avoid joints.','Skipping sore spots — those are the spots that need the most attention.'] },
  { id:'wu-19',name:'Static Stretch Cooldown',category:'Warmup & Cooldown',duration:8,difficulty:'beginner',equipment:[],type:'warmup',
    summary:'Post-workout static stretching to improve flexibility and prevent soreness.',
    steps:['Hamstring stretch: sit and reach for your toes. Hold 30 seconds.','Quad stretch: standing, pull heel to butt. 30 seconds each.','Groin stretch: butterfly — soles of feet together, push knees down. 30 seconds.','Hip flexor stretch: kneeling lunge. 30 seconds each.','Calf stretch against a wall. 30 seconds each.','Shoulder stretch across your body. 30 seconds each arm.'],
    coachingPoints:['Static stretching is for AFTER workouts, not before.','Hold each stretch — don\'t bounce.','Breathe deeply during each stretch.','Stretching after workouts reduces soreness and improves flexibility over time.'],
    commonMistakes:['Doing static stretching before playing — save it for after.','Not holding long enough — 30 seconds minimum.','Bouncing in the stretch.'] },
  { id:'wu-20',name:'Deep Breathing Cooldown',category:'Warmup & Cooldown',duration:3,difficulty:'beginner',equipment:[],type:'warmup',
    summary:'Calm your nervous system after an intense workout with controlled breathing.',
    steps:['Sit or lie down comfortably.','Breathe in through your nose for 4 seconds.','Hold for 4 seconds.','Breathe out through your mouth for 6 seconds.','Repeat for 3 minutes.'],
    coachingPoints:['This activates your recovery system — you recover faster.','Your heart rate will drop noticeably within 1-2 minutes.','This is what elite athletes do after training — it works.','Use this before free throws in games to calm down.'],
    commonMistakes:['Breathing too fast — slow it down.','Skipping this — recovery is part of training.','Not fully emptying your lungs on the exhale.'] },
  { id:'wu-21',name:'Mobility Flow',category:'Warmup & Cooldown',duration:5,difficulty:'beginner',equipment:[],type:'warmup',
    summary:'A continuous flow of mobility movements to warm up your entire body.',
    steps:['Start standing. Reach high overhead (5 seconds).','Fold forward, touch your toes (5 seconds).','Walk your hands out to a plank position (5 seconds).','Drop your hips into an up-dog position (5 seconds).','Push back into down-dog (5 seconds).','Walk your feet to your hands, roll up to standing.','Repeat 5 times slowly and smoothly.'],
    coachingPoints:['Flow smoothly between positions — no jerking.','Breathe deeply throughout.','This warms up everything: shoulders, back, hips, hamstrings, calves.','Great for mornings or pre-training.'],
    commonMistakes:['Rushing through it — be smooth and slow.','Holding your breath.','Skipping positions.'] },
  { id:'wu-22',name:'Frankenstein Walk',category:'Warmup & Cooldown',duration:2,difficulty:'beginner',equipment:[],type:'warmup',
    summary:'Straight-leg kicks while walking to dynamically stretch hamstrings.',
    steps:['Walk forward. Kick your right leg straight up toward your outstretched left hand.','Step and kick left leg to your right hand.','Keep legs straight — like Frankenstein walking.','10 each leg.'],
    coachingPoints:['Keep the kicking leg straight.','Reach for your toes, don\'t lean down.','This dynamically stretches your hamstrings more effectively than sitting and reaching.'],
    commonMistakes:['Bending the kicking knee.','Leaning way forward.','Not kicking high enough.'] },
  { id:'wu-23',name:'Heel Walk',category:'Warmup & Cooldown',duration:2,difficulty:'beginner',equipment:[],type:'warmup',
    summary:'Walk on your heels to activate shin muscles and improve ankle strength.',
    steps:['Lift your toes off the ground so you\'re standing on your heels.','Walk forward for 30 seconds — toes never touching the ground.','Turn around and walk back.','3 trips.'],
    coachingPoints:['This strengthens the muscles on the front of your shin.','Helps prevent shin splints — common in basketball players.','Keep your toes as high as possible.'],
    commonMistakes:['Toes touching the ground — keep them up.','Going too fast — controlled pace.'] },
  { id:'wu-24',name:'Toe Walk',category:'Warmup & Cooldown',duration:2,difficulty:'beginner',equipment:[],type:'warmup',
    summary:'Walk on your toes to strengthen calves and improve balance.',
    steps:['Rise up on your toes — heels completely off the ground.','Walk forward for 30 seconds.','Turn around and walk back.','3 trips.'],
    coachingPoints:['Get as high on your toes as possible.','This strengthens your calves for jumping and sprinting.','Keep your core engaged for balance.'],
    commonMistakes:['Heels dropping down.','Rushing — controlled pace.','Losing balance — engage core.'] },
  { id:'wu-25',name:'Light Layup Warmup',category:'Warmup & Cooldown',duration:5,difficulty:'beginner',equipment:['ball','hoop'],type:'warmup',
    summary:'Easy layup lines to get your body moving and build touch before training.',
    steps:['Right hand layups — 10 at an easy pace.','Left hand layups — 10.','Reverse layups — 5 each side.','Floaters from the lane — 5 each side.','Keep it light and smooth. This is NOT a conditioning drill.'],
    coachingPoints:['Focus on footwork and touch, not speed.','Get your body used to finishing at the rim.','This should feel easy and comfortable.'],
    commonMistakes:['Going too hard — this is a warmup.','Only doing right hand — always warm up both sides.'] },
];

