// ============================================================
// BASKETBALL IQ (25 drills)
// ============================================================
const BASKETBALL_IQ_DRILLS: Drill[] = [
  { id:'iq-1',name:'Read and React Drill',category:'Basketball IQ',duration:10,difficulty:'intermediate',equipment:['ball','hoop','cones'],type:'skill',
    summary:'Practice reading the defense and making the correct play from multiple situations.',
    steps:['Set up cones representing defenders in different positions.','Start at the top of the key with the ball.','Read the cone positions and decide: shoot, drive, or pass.','If the "defender" is far off: shoot.','If the "defender" is tight: drive past.','If two "defenders" help: pass to the open spot.','10 reps, randomize cone positions each time.'],
    coachingPoints:['Basketball is a read-and-react game.','Don\'t decide before you read — let the defense tell you what\'s open.','Quick decisions — in a game you have less than 2 seconds.','Practice making the RIGHT play, not the flashy play.'],
    commonMistakes:['Pre-determining your move.','Taking too long to decide.','Always choosing the same option.'] },
  { id:'iq-2',name:'Advantage Disadvantage Drill',category:'Basketball IQ',duration:10,difficulty:'intermediate',equipment:['ball','court','partners'],type:'skill',
    summary:'Play with advantages (3v2, 4v3) and disadvantages (2v3) to learn decision-making.',
    steps:['Start 3 offensive players vs 2 defenders.','Offense must score within 5 seconds — find the open man fast.','After the make or stop, add a defender. Now it\'s 3v3.','Play 3v3 for one possession.','Rotate. 10 rounds.'],
    coachingPoints:['With an advantage, ATTACK. Don\'t let the defense set up.','Find the numbers. 3v2 means someone is ALWAYS open.','When it goes to even numbers, play smart — use the advantage you created.','This is how fast breaks work in real games.'],
    commonMistakes:['Holding the ball too long in an advantage.','Not finding the open man.','Playing too slowly when you have numbers.'] },
  { id:'iq-3',name:'Pick and Roll Read Drill',category:'Basketball IQ',duration:10,difficulty:'advanced',equipment:['ball','hoop','cones'],type:'skill',
    summary:'Walk through all pick-and-roll options based on defensive coverage.',
    steps:['Cone at top of key (screener).','Dribble toward screen. Read defense:','Over screen: pull up jumper.','Under screen: drive hard.','Big hedges: split and attack.','Big drops: pull up mid-range.','5 reps each read, then 10 random.'],
    coachingPoints:['Read, don\'t decide beforehand.','Set up defender before using screen.','Eyes up — see the whole floor.'],
    commonMistakes:['Pre-determining move.','Too fast into the screen.','Ignoring screener\'s roll.'] },
  { id:'iq-4',name:'Drive and Kick Drill',category:'Basketball IQ',duration:8,difficulty:'intermediate',equipment:['ball','hoop','partners'],type:'skill',
    summary:'Practice driving to draw help defense, then kicking out to an open shooter.',
    steps:['3 offensive players: ball handler at top, shooters in corners.','Drive to the basket. Draw the help defender.','When the help comes, kick the ball out to the open corner shooter.','Corner shooter catches and shoots.','Rotate positions. 10 rounds.'],
    coachingPoints:['Drive with your eyes up — you need to see the open man.','The kick-out pass should be a quick, accurate chest pass.','The corner shooter should be ready before the pass comes.','This is the most common play in modern basketball.'],
    commonMistakes:['Driving with your head down.','Forcing a shot when the kick-out is open.','Bad pass on the kick-out — has to be on target.'] },
  { id:'iq-5',name:'Help Defense Rotation Drill',category:'Basketball IQ',duration:10,difficulty:'advanced',equipment:['court','4 partners'],type:'skill',
    summary:'Practice team defensive rotations when the ball drives into the paint.',
    steps:['4 offensive players spread around the three-point line. 4 defenders.','Ball handler drives to the basket.','Help defender rotates to stop the drive.','Other defenders rotate to cover the open man.','Play out the possession.','Reset and repeat from different starting points.'],
    coachingPoints:['Help side defender must help AND the other defenders must rotate.','Communicate! Call out "help" and "rotate."','The goal is to have no open shooters after the rotation.','This is what separates good defensive teams from bad ones.'],
    commonMistakes:['Help defender not helping — the drive gets a layup.','Other defenders not rotating — open three pointer.','No communication.'] },
  { id:'iq-6',name:'Transition Decision Drill',category:'Basketball IQ',duration:8,difficulty:'intermediate',equipment:['ball','hoop'],type:'skill',
    summary:'Read the numbers in transition and make the right play at full speed.',
    steps:['Start at the far baseline.','Push the ball full court. At the other end, read:','3v2: attack and find the open man.','2v1: attack the defender, pass or score based on their choice.','1v1: slow down, set up your move.','5 reps of each situation.'],
    coachingPoints:['Speed is your weapon in transition — push it.','Read the numbers: 3v2, 2v1, 1v1.','Don\'t pass up a layup for a three.','If defense is set, slow down and run offense.'],
    commonMistakes:['Forcing a bad play at full speed.','Not looking for teammates.','Stopping at the three-point line instead of attacking.'] },
  { id:'iq-7',name:'Shot Selection Drill',category:'Basketball IQ',duration:10,difficulty:'intermediate',equipment:['ball','hoop'],type:'skill',
    summary:'Practice taking only good shots and passing up bad ones.',
    steps:['Simulate game situations. For each one, decide: shoot or pass.','Catch on the wing — defender 3 feet away: PASS. Wait for a better shot.','Catch on the wing — wide open: SHOOT.','Off the dribble — contested: PASS.','Off a screen — quick release: SHOOT.','Track your decisions. Review what was a good vs bad shot.'],
    coachingPoints:['A good shot is: open, in rhythm, in your range, in your spot.','A bad shot is: contested, rushed, out of range, or off-balance.','The best scorers take the RIGHT shots, not the most shots.','If you take only good shots, your percentage goes way up.'],
    commonMistakes:['Shooting everything.','Not shooting when you\'re actually open.','Ignoring what the defense gives you.'] },
  { id:'iq-8',name:'Clock Management Drill',category:'Basketball IQ',duration:10,difficulty:'advanced',equipment:['ball','hoop','shot clock or timer'],type:'skill',
    summary:'Practice managing the shot clock and end-of-game situations.',
    steps:['Set a shot clock (or timer) to 24 seconds.','Play offense and take a shot before the clock expires.','Then set it to 10 seconds: get a good shot in limited time.','Then set it to 5 seconds: immediate attack for a score.','Practice end-of-game: down 2, 8 seconds left. What do you do?','Practice: down 3, 5 seconds left. What do you do?'],
    coachingPoints:['Always know the shot clock and game clock.','With lots of time: run offense, be patient.','With limited time: attack immediately, no wasted dribbles.','End of game situations: know whether you need a 2 or 3, and act accordingly.'],
    commonMistakes:['Not being aware of the clock.','Rushing when there\'s still time.','Taking a 2 when you need a 3.'] },
  { id:'iq-9',name:'Situational Scrimmage',category:'Basketball IQ',duration:15,difficulty:'advanced',equipment:['ball','hoop','partners'],type:'skill',
    summary:'Practice specific game situations in scrimmage format.',
    steps:['Set up a specific game situation: down 5 with 2 minutes left.','Play it out. Both teams play as if it\'s a real game.','After the scenario, reset with a different situation.','Scenarios: up 3 last possession, tied with 30 seconds, down 1 with ball.','Discuss what each team did right and wrong after each scenario.'],
    coachingPoints:['This is the most game-like drill you can do.','Think about what you would do in each situation BEFORE the ball is tipped.','Clock management, shot selection, and defensive intensity all matter.','The team that practices these situations wins close games.'],
    commonMistakes:['Not taking it seriously — treat it like a real game.','Poor clock awareness.','Panicking in pressure situations.'] },
  { id:'iq-10',name:'3 on 2 Continuous',category:'Basketball IQ',duration:10,difficulty:'intermediate',equipment:['ball','hoop','4 partners'],type:'skill',
    summary:'Non-stop 3-on-2 to build transition offense and defense decision-making.',
    steps:['3 offense vs 2 defense going one direction.','After the play (make or miss), 2 defenders get the ball and push the other way.','1 offensive player sprints back to play defense, making it 2v1.','A new player joins from the sideline to make it 3v2 again.','Continuous. Play for 5 minutes.'],
    coachingPoints:['Offense: attack before the defense sets up.','Offense: find the open man — someone is always open in 3v2.','Defense: protect the basket first, then close out.','Defense: one protects the rim, one takes the ball.'],
    commonMistakes:['Offense going too slow — you have the numbers, attack!','Defense not communicating who takes ball vs who protects rim.','New player not sprinting in fast enough.'] },
  { id:'iq-11',name:'4 on 3 Advantage Drill',category:'Basketball IQ',duration:10,difficulty:'intermediate',equipment:['ball','hoop','6 partners'],type:'skill',
    summary:'Play with a 4-on-3 advantage to practice finding and attacking the open man.',
    steps:['4 offensive players vs 3 defenders.','Offense must find the open man and score.','Play the possession out. If offense scores or gets a stop, they stay on offense.','Rotate after every 3 possessions.'],
    coachingPoints:['In 4v3, someone is ALWAYS open. Find them.','Move the ball quickly — the defense can\'t guard everyone.','The extra pass usually leads to an even more open shot.','This teaches you to see the floor and make the right pass.'],
    commonMistakes:['Holding the ball instead of moving it.','Forcing a shot when a teammate is more open.','Slow ball movement — the defense rotates if you\'re slow.'] },
  { id:'iq-12',name:'No Dribble Scrimmage',category:'Basketball IQ',duration:10,difficulty:'intermediate',equipment:['ball','hoop','partners'],type:'skill',
    summary:'Play a scrimmage where no one can dribble — forces passing, cutting, and movement.',
    steps:['Full scrimmage rules but NO DRIBBLING allowed.','You can catch and shoot or catch and pass.','To move with the ball, you must pass it.','Play to 11 points.'],
    coachingPoints:['This teaches ball movement — the most important offensive concept.','You\'ll learn to cut hard because that\'s the only way to get open.','Communication skyrockets because you have to work together.','Every player touches the ball because you can\'t just dribble it yourself.'],
    commonMistakes:['Holding the ball — you have to pass immediately or shoot.','Standing still — if you don\'t have the ball, CUT.','Forgetting and dribbling — that\'s a turnover.'] },
  { id:'iq-13',name:'One Dribble Scrimmage',category:'Basketball IQ',duration:10,difficulty:'intermediate',equipment:['ball','hoop','partners'],type:'skill',
    summary:'Scrimmage with only one dribble allowed per catch — builds efficiency and decision-making.',
    steps:['Full scrimmage but you can only take ONE dribble per catch.','Catch the ball, take your one dribble, then pass or shoot.','Play to 11 points.'],
    coachingPoints:['One dribble forces you to make quick decisions.','Use your dribble to create an advantage: drive past the defender or create a passing angle.','Don\'t waste your dribble — make it count.','This eliminates dribbling aimlessly, which is the biggest IQ killer.'],
    commonMistakes:['Wasting the dribble — don\'t just bounce it.','Taking two dribbles — that\'s a turnover.','Not catching in triple threat — be ready to make a play.'] },
  { id:'iq-14',name:'Spacing Drill',category:'Basketball IQ',duration:10,difficulty:'intermediate',equipment:['ball','court'],type:'skill',
    summary:'Understand where to be on the court when you don\'t have the ball.',
    steps:['Walk through 5 positions: corners, wings, top of key.','Pass and relocate: after every pass, move to a new spot.','Rule: 12-15 feet between every player.','When someone drives, drift to an open spot for a kick-out.','10 minutes walking through proper spacing.'],
    coachingPoints:['Spacing is the most important concept in basketball.','If you\'re next to a teammate, one of you is wrong.','When ball moves, you move.','Be in a spot where you can catch and shoot in rhythm.'],
    commonMistakes:['Standing still after passing.','Drifting toward the ball.','Being in the same area as a teammate.'] },
  { id:'iq-15',name:'Backdoor Cut Drill',category:'Basketball IQ',duration:8,difficulty:'intermediate',equipment:['ball','hoop','partner'],type:'skill',
    summary:'Practice the backdoor cut — when the defender overplays you, cut to the basket.',
    steps:['Start on the wing. Partner at the top of key with the ball.','Set up your cut: take 2 steps toward the ball.','Sell the overplay: make the "defender" think you want the ball at the wing.','Spin and cut HARD to the basket.','Partner throws a bounce pass. Finish with a layup.','10 reps each side.'],
    coachingPoints:['The setup is everything — make it look like you want the ball at the wing.','The cut has to be EXPLOSIVE — slow cuts don\'t work.','Call for the ball as you cut so your partner knows.','The bounce pass is the best pass for backdoor cuts — chest passes get stolen.'],
    commonMistakes:['Not setting up the cut — just randomly cutting.','Slow cut — has to be explosive.','Cutting too early before the setup.'] },
  { id:'iq-16',name:'Give and Go Drill',category:'Basketball IQ',duration:8,difficulty:'beginner',equipment:['ball','hoop','partner'],type:'skill',
    summary:'The simplest play in basketball — pass and immediately cut to the basket.',
    steps:['Start at the wing with the ball. Partner at the top of key.','Pass to your partner.','IMMEDIATELY cut hard to the basket.','Partner passes back to you. Finish with a layup.','10 reps each side. Switch roles.'],
    coachingPoints:['Pass and CUT — don\'t pass and watch.','The cut has to be immediate — before the defender reacts.','This is basketball\'s oldest and most effective play.','Show your hand where you want the return pass.'],
    commonMistakes:['Passing and standing.','Slow cut after the pass.','Not showing a target for the return pass.'] },
  { id:'iq-17',name:'Closeout Decision Drill',category:'Basketball IQ',duration:8,difficulty:'advanced',equipment:['ball','hoop','partner'],type:'skill',
    summary:'Practice reading the closeout and making the right decision: shoot, drive, or pass.',
    steps:['Partner starts at the rim. You\'re at the three-point line with the ball.','Partner closes out at different speeds: hard, soft, or not at all.','If hard closeout: drive past them.','If soft closeout: shoot the three.','If no closeout: shoot immediately.','10 reps. Partner varies their closeout.'],
    coachingPoints:['This is the #1 decision you\'ll make in a game.','Read their speed: fast = drive, slow = shoot.','Don\'t decide before you read — let them tell you what to do.','Quick decisions beat the defense.'],
    commonMistakes:['Always shooting regardless.','Not reading the closeout speed.','Taking too long to decide.'] },
  { id:'iq-18',name:'Extra Pass Drill',category:'Basketball IQ',duration:8,difficulty:'intermediate',equipment:['ball','hoop','2 partners'],type:'skill',
    summary:'Practice making one more pass to get a better shot — the "extra pass" creates open looks.',
    steps:['3 players: ball handler and 2 shooters.','Ball handler drives and kicks out to shooter 1.','Shooter 1 could shoot... but makes the EXTRA pass to shooter 2 who is wide open.','Shooter 2 shoots.','10 rounds. Track the open three-point percentage.'],
    coachingPoints:['A good shot is nice. A GREAT shot is one extra pass away.','The extra pass leads to wide open shots because the defense over-rotates.','Unselfish teams shoot higher percentages than selfish ones.','This is how the best teams in basketball operate.'],
    commonMistakes:['Shooting a good shot instead of passing for a great shot.','Making the extra pass when you\'re actually wide open — know when to shoot.','Bad extra passes that get stolen.'] },
  { id:'iq-19',name:'Skip Pass Drill',category:'Basketball IQ',duration:6,difficulty:'intermediate',equipment:['ball','2 partners'],type:'skill',
    summary:'Practice the skip pass — a cross-court pass that moves the ball faster than the defense can rotate.',
    steps:['3 players: ball handler on right wing, shooters on left wing and left corner.','Ball handler throws a skip pass (two-hand overhead) to the left corner.','Corner shooter catches and shoots or makes one more pass.','10 reps to each target.','Focus on accuracy and speed of the pass.'],
    coachingPoints:['The skip pass travels faster than the defense can rotate — it creates open shots.','Two-hand overhead pass is the best technique — accurate and fast.','Aim for the shooter\'s chest — don\'t make them reach.','This pass is especially effective against zone defense.'],
    commonMistakes:['Pass too slow — the defense rotates and steals it.','Inaccurate pass — hitting the receiver in the feet or over their head.','Using a one-hand pass — use two hands for accuracy.'] },
  { id:'iq-20',name:'Offensive Rebound Decision Drill',category:'Basketball IQ',duration:8,difficulty:'intermediate',equipment:['ball','hoop','partner'],type:'skill',
    summary:'Practice making the right decision after grabbing an offensive rebound.',
    steps:['Partner shoots. You crash the boards for the offensive rebound.','After the rebound, make a quick decision:','If you\'re close to the rim: go right back up for a putback.','If there\'s a defender on you: kick it out to an open shooter.','If you\'re off balance: secure the ball and reset the offense.','15 reps. Practice all three decisions.'],
    coachingPoints:['The decision has to be instant — no time to think.','Putback if you\'re open and close. Kick out if you\'re not.','Keep the ball high after the rebound — don\'t bring it down.','Offensive rebounds are the highest value plays in basketball.'],
    commonMistakes:['Always going back up when a defender is right there.','Bringing the ball down and getting it stripped.','Not kicking it out when a teammate is wide open.'] },
  { id:'iq-21',name:'End of Game Situations',category:'Basketball IQ',duration:10,difficulty:'advanced',equipment:['ball','hoop','partners'],type:'skill',
    summary:'Walk through critical end-of-game scenarios to be prepared when they happen.',
    steps:['Scenario 1: Down 1, 10 seconds, your ball. What do you do?','Scenario 2: Up 3, opponent has ball, 15 seconds. How do you defend?','Scenario 3: Tied, 5 seconds, opponent shooting free throws. How do you set up for the rebound?','Scenario 4: Down 3, 4 seconds, inbounding under your basket.','Walk through each scenario. Discuss. Then execute at game speed.'],
    coachingPoints:['Know these situations BEFORE they happen in a game.','Down 1 = you need a 2. Attack the basket.','Up 3 = foul before they shoot a 3 (controversial but effective).','Down 3 with 4 seconds = sprint to three-point line and shoot immediately.'],
    commonMistakes:['Not having a plan — the game is too fast to figure it out in the moment.','Taking a 2 when you need a 3.','Fouling a three-point shooter when you\'re up 3.'] },
  { id:'iq-22',name:'Press Break Drill',category:'Basketball IQ',duration:8,difficulty:'intermediate',equipment:['ball','court','3 partners'],type:'skill',
    summary:'Practice breaking a full-court press without turning the ball over.',
    steps:['4 offensive players vs full court press defense.','Inbounder passes to the player who gets open.','Use the middle of the floor — it\'s the hardest area to press.','Advance the ball past half court with passing, not just dribbling.','If trapped, find the open man.','10 reps.'],
    coachingPoints:['Don\'t panic. The press works because teams panic.','The middle of the floor is the escape route — always have someone there.','If you get trapped, someone is open. Find them.','Pass over the press when possible — a long pass beats press every time.'],
    commonMistakes:['Panicking and throwing bad passes.','Dribbling into traps.','Everyone running to the ball instead of spreading out.'] },
  { id:'iq-23',name:'Zone Offense Drill',category:'Basketball IQ',duration:10,difficulty:'intermediate',equipment:['ball','hoop','partners'],type:'skill',
    summary:'Practice attacking a zone defense by finding the gaps.',
    steps:['Set up a 2-3 zone (cones or players).','Offensive players move the ball around the zone quickly.','Look for gaps: the high post, the short corner, the wing.','The ball moves faster than the zone can shift.','When a gap opens: attack it with a pass or a dribble.','Practice for 10 minutes, rotating positions.'],
    coachingPoints:['Against a zone, the ball has to MOVE. Quick passes beat zones.','Attack the gaps — the space between two zone defenders.','The high post (free throw line) is the most dangerous spot against a zone.','A zone is beaten by ball movement and shooting — not by one player dribbling.'],
    commonMistakes:['One player trying to beat the zone by themselves.','Slow ball movement — the zone adjusts.','Not attacking the gaps.'] },
  { id:'iq-24',name:'Defensive Communication Drill',category:'Basketball IQ',duration:8,difficulty:'intermediate',equipment:['court','partners'],type:'skill',
    summary:'Practice talking on defense — calling out screens, switches, and help.',
    steps:['5 on 5 half court. Offense runs plays.','Defense must TALK on every action.','Call out: "Screen left!" "Switch!" "Help!" "I got ball!" "Deny!"','If the defense doesn\'t call out a screen, offense gets a free point.','Play for 5 minutes. Track communication points.'],
    coachingPoints:['Defense is 80% communication and 20% athleticism.','If you see a screen coming, your voice helps your teammate more than anything.','Talk EARLY — don\'t wait until the screen hits.','Every defensive action should have a verbal call.'],
    commonMistakes:['Being silent on defense.','Calling out too late — you need to warn teammates early.','Only one person talking — the whole team needs to communicate.'] },
  { id:'iq-25',name:'Film Study Session',category:'Basketball IQ',duration:15,difficulty:'beginner',equipment:['phone or computer'],type:'skill',
    summary:'Watch game film of yourself or a pro player and break down what\'s happening.',
    steps:['Pick a full game or half of game film (yours or a pro player at your position).','Watch the whole thing once without stopping.','Watch it again. Pause after every 5 possessions.','For each possession, ask: What was the right play? Was it made?','Write down 3 things to work on based on what you saw.'],
    coachingPoints:['Film study is the fastest way to improve your basketball IQ.','Watch your own film with an honest eye — don\'t just watch highlights.','If watching a pro, watch the player at YOUR position and copy their movement.','3 takeaways per film session. Then go work on them.'],
    commonMistakes:['Only watching highlights — watch the whole game.','Not taking notes — you\'ll forget what you saw.','Watching but not applying what you learned to practice.'] },
  { id:'iq-26',name:'Head Up Dribble Drill',category:'Basketball IQ',duration:6,difficulty:'beginner',equipment:['ball','partner or wall'],type:'skill',
    summary:'Dribble while watching a partner\'s hand signals — forces your eyes off the ball.',
    steps:['Partner stands 10 feet in front of you with both hands ready.','You start dribbling. Partner randomly holds up 1, 2, 3, 4, or 5 fingers on either hand.','You call out the number out loud — the moment you see it.','30 seconds of dribbling and calling numbers.','Then do the drill while doing crossovers, between-legs, and behind-back.','5 rounds of 30 seconds each.'],
    coachingPoints:['If you\'re looking at the ball, you\'re not seeing the floor.','In a game, the open man is only open for half a second — your eyes have to find them.','Court vision starts with the ability to dribble without looking.','This is the foundation of all passing and decision making.'],
    commonMistakes:['Glancing down at the ball — keep your eyes up.','Slow reactions — call the number the instant you see it.','Sloppy dribble when not looking — practice until it\'s clean.'] },
  { id:'iq-27',name:'Scan and Pass Drill',category:'Basketball IQ',duration:8,difficulty:'intermediate',equipment:['ball','3 partners','court'],type:'skill',
    summary:'Catch the ball, scan the floor, and pass to whoever raises their hand — builds floor awareness.',
    steps:['You stand at the top of the key. 3 partners spread around the court (corners, wing).','One partner randomly raises their hand for 1 second.','You catch a pass (toss to yourself), scan the floor, find the raised hand, pass to them.','After the pass, they put their hand down and a different partner raises theirs.','You sprint to a new spot, catch, scan, pass.','10 rounds of continuous scanning and passing.'],
    coachingPoints:['Before you catch the ball, you should already be scanning.','Your eyes should be moving constantly — see the floor before the ball arrives.','The best passers don\'t need time to think — they already know where everyone is.','Scan, decide, pass. All in under 1 second.'],
    commonMistakes:['Catching first, then looking — be looking before you catch.','Only finding one teammate and ignoring the others.','Slow scans — you have less than a second in a real game.'] },
  { id:'iq-28',name:'Peripheral Vision Drill',category:'Basketball IQ',duration:6,difficulty:'intermediate',equipment:['ball','2 partners'],type:'skill',
    summary:'Focus on a fixed point ahead while reading peripheral movement — true court vision.',
    steps:['Stand at the top of the key with the ball.','Partner 1 stands directly in front of you 15 feet away. Stare at them.','Partner 2 stands at the wing — in your peripheral vision but NOT where you\'re looking.','Without moving your eyes from partner 1, partner 2 raises a number of fingers.','You call out the number using only peripheral vision.','15 reps. Then switch which side partner 2 stands on.'],
    coachingPoints:['Real court vision means seeing teammates without looking at them.','Your peripheral vision can detect movement and shapes — train it.','Look at the rim or your defender, but SEE the cutters and shooters with your peripheral.','This is what makes elite passers look like they have eyes in the back of their head.'],
    commonMistakes:['Cheating by glancing at the side — eyes stay locked forward.','Giving up because it feels impossible — it gets better with practice.','Not training this skill at all — most players ignore it, which is why most players can\'t see the floor.'] },
];

